from datetime import datetime, timedelta
from typing import Optional
from jose import JWTError, jwt
from passlib.context import CryptContext
from fastapi import Depends, HTTPException, status
from fastapi.security import OAuth2PasswordBearer

from app.core.config import settings
from app.core.database import get_db
from app.models.user import User

# Password hashing
pwd_context = CryptContext(schemes=["bcrypt"], deprecated="auto")

# OAuth2 scheme
oauth2_scheme = OAuth2PasswordBearer(tokenUrl="/api/auth/login")


def verify_password(plain_password=***REDACTED***, hashed_password=***REDACTED*** -> bool:
    """Verify a password against a hash"""
    return pwd_context.verify(plain_password, hashed_password)


def get_password_hash(password=***REDACTED*** -> str:
    """Hash a password"""
    return pwd_context.hash(password)


def create_access_token(data: dict, expires_delta: Optional[timedelta] = None) -> str:
    """Create a JWT access token"""
    to_encode = data.copy()
    
    if expires_delta:
        expire = datetime.utcnow() + expires_delta
    else:
        expire = datetime.utcnow() + timedelta(minutes=settings.ACCESS_TOKEN_EXPIRE_MINUTES)
    
    to_encode.update({"exp": expire})
    encoded_jwt = jwt.encode(to_encode, settings.SECRET_KEY, algorithm=settings.ALGORITHM)
    
    return encoded_jwt


def get_current_user(
    token=***REDACTED*** = Depends(oauth2_scheme),
    db = Depends(get_db)
) -> User:
    """Get the current authenticated user"""
    from app.models.user_settings import UserSession
    
    credentials_exception = HTTPException(
        status_code=status.HTTP_401_UNAUTHORIZED,
        detail="Could not validate credentials",
        headers={"WWW-Authenticate": "Bearer"},
    )
    
    try:
        payload = jwt.decode(token, settings.SECRET_KEY, algorithms=[settings.ALGORITHM])
        user_id: str = payload.get("sub")
        jti: str = payload.get("jti")  # Get JTI from token
        
        if user_id is None:
            raise credentials_exception
        
        # Check if session is revoked (if JTI exists)
        if jti:
            session = db.query(UserSession).filter(
                UserSession.token_jti == jti,
                UserSession.user_id == int(user_id)
            ).first()
            
            if session and session.is_revoked:
                raise HTTPException(
                    status_code=status.HTTP_401_UNAUTHORIZED,
                    detail="Session has been revoked",
                    headers={"WWW-Authenticate": "Bearer"},
                )
            
            # Update last_active_at
            if session:
                session.last_active_at = datetime.utcnow()
                db.commit()
            
    except JWTError:
        raise credentials_exception
    
    # Get user from database
    user = db.query(User).filter(User.id == int(user_id)).first()
    
    if user is None:
        raise credentials_exception
    
    if not user.is_active:
        raise HTTPException(status_code=400, detail="Inactive user")
    
    return user


def get_current_active_user(
    current_user: User = Depends(get_current_user)
) -> User:
    """Get the current active user"""
    if not current_user.is_active:
        raise HTTPException(status_code=400, detail="Inactive user")
    return current_user


def get_current_superuser(
    current_user: User = Depends(get_current_user)
) -> User:
    """Get the current superuser (admin)"""
    if not current_user.is_superuser:
        raise HTTPException(
            status_code=status.HTTP_403_FORBIDDEN,
            detail="Not enough permissions. Admin access required."
        )
    return current_user



def require_roles(allowed_roles: list[str]):
    """
    Dependency to require specific roles
    Usage: current_user: User = Depends(require_roles(["admin", "super_admin"]))
    """
    def role_checker(current_user: User = Depends(get_current_user)) -> User:
        # Check role field first
        if hasattr(current_user, 'role') and current_user.role:
            if current_user.role in allowed_roles:
                return current_user
        
        # Fallback: check is_superuser for backward compatibility
        if current_user.is_superuser and ("admin" in allowed_roles or "super_admin" in allowed_roles):
            return current_user
        
        raise HTTPException(
            status_code=status.HTTP_403_FORBIDDEN,
            detail="Permission denied. Required roles: " + ", ".join(allowed_roles)
        )
    
    return role_checker


def can_access_admin(user: User) -> bool:
    """Check if user can access admin features"""
    if not user:
        return False
    
    # Check role field
    if hasattr(user, 'role') and user.role:
        if user.role in ["admin", "super_admin"]:
            return True
    
    # Fallback: check is_superuser
    if user.is_superuser:
        return True
    
    return False

