                      ? 'bg-indigo-600 text-white border-indigo-600 shadow-sm shadow-indigo-500/20'
                      : 'bg-[#1E293B] text-gray-300 border-gray-700 hover:border-indigo-500/50 hover:bg-[#1E293B]/80'
                  }`}
                >
