              {/* Platform */}
              <h4 className="text-[11px] text-gray-500 font-semibold uppercase tracking-wider mb-2">Nền tảng</h4>
              <div className="flex flex-wrap gap-1.5 mb-4">
                {SOURCE_TYPE_OPTIONS.map((st) => (
