              <div className="text-4xl font-black text-emerald-600">{data?.metrics?.sentiment?.positive || 0}</div>
              <div className="text-sm text-gray-500 mb-1">Tích cực</div>
            </div>
            <div className="flex items-center space-x-4 mt-3 text-sm">
