                    onClick={() => setShowRequestDetail(false)}
                    className="px-5 py-2.5 text-gray-300 bg-[#111827] border border-gray-700 rounded-xl hover:bg-gray-800 hover:text-white transition-colors font-medium"
                  >
                    Đóng
                  </button>
                  
                  <div className="flex space-x-3">
                    {selectedRequest.approval_status === 'pending' && (
                      <>
                        <button
                          onClick={() => handleRejectRequest(selectedRequest.id)}
                          className="px-5 py-2.5 text-rose-400 bg-rose-500/10 border border-rose-500/20 rounded-xl hover:bg-rose-500/20 transition-colors font-medium"
                        >
                          Từ chối
                        </button>
                        <button
                          onClick={() => handleApproveRequest(selectedRequest.id)}
                          className="px-5 py-2.5 text-emerald-400 bg-emerald-500/10 border border-emerald-500/20 rounded-xl hover:bg-emerald-500/20 transition-colors font-medium"
                        >
                          Phê duyệt
                        </button>
                      </>
                    )}
                    
                    {(selectedRequest.status === 'in_progress' || selectedRequest.status === 'waiting_external_response') && (
                      <button
                        onClick={() => handleCompleteRequest(selectedRequest.id)}
                        className="px-5 py-2.5 text-white bg-indigo-600 rounded-xl hover:bg-indigo-700 transition-colors font-medium shadow-sm shadow-indigo-500/20"
                      >
                        Hoàn thành
                      </button>
                    )}
                    
                    {selectedRequest.status === 'approved' && (
                      <button
                        onClick={async () => {
                          try {
                            await serviceRequestsApi.update(selectedRequest.id, { status: 'in_progress' });
                            toast.success('Đã chuyển sang trạng thái đang xử lý!');
                            fetchData();
                            setShowRequestDetail(false);
                          } catch (error: any) {
                            toast.error('Lỗi khi cập nhật trạng thái');
                          }
                        }}
                        className="px-5 py-2.5 text-white bg-indigo-600 rounded-xl hover:bg-indigo-700 transition-colors font-medium shadow-sm shadow-indigo-500/20"
                      >
                        Bắt đầu xử lý
                      </button>
                    )}
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Create Service Request Modal */}
      {showCreateRequest && selectedService && (
        <div className="fixed inset-0 z-[60] overflow-y-auto">
          <div className="fixed inset-0 bg-black/70 backdrop-blur-sm transition-opacity" onClick={() => setShowCreateRequest(false)} />
          <div className="flex min-h-full items-center justify-center p-4">
            <div className="relative bg-[#111827] border border-gray-800 rounded-2xl shadow-2xl w-full max-w-3xl transform transition-all overflow-hidden flex flex-col max-h-[90vh]">
              <div className="p-6 border-b border-gray-800 bg-[#1E293B]/30 shrink-0">
                <div className="flex items-center justify-between">
                  <div>
                    <h2 className="text-xl font-bold text-white">Tạo Yêu Cầu Dịch Vụ</h2>
                    <p className="text-sm text-gray-400 mt-1">{selectedService.name}</p>
                  </div>
                  <button
                    onClick={() => setShowCreateRequest(false)}
                    className="text-gray-500 hover:text-gray-300 transition-colors"
                  >
                    <XCircle className="w-6 h-6" />
                  </button>
                </div>
              </div>
              
              <div className="p-6 space-y-6 overflow-y-auto">
                {/* Service Info */}
                <div className="bg-indigo-500/10 border border-indigo-500/20 rounded-xl p-5">
                  <div className="grid grid-cols-2 gap-6 text-sm">
                    <div className="flex flex-col">
                      <span className="text-xs font-semibold text-indigo-400/80 uppercase tracking-wider mb-1">Danh mục</span>
                      <span className="font-medium text-white">{selectedService.category.name}</span>
                    </div>
                    <div className="flex flex-col">
                      <span className="text-xs font-semibold text-indigo-400/80 uppercase tracking-wider mb-1">Giá cơ bản</span>
                      <span className="font-bold text-indigo-400">
                        {selectedService.base_price ? formatPrice(selectedService.base_price) : 'Thỏa thuận'}
                      </span>
                    </div>
                    <div className="flex flex-col">
                      <span className="text-xs font-semibold text-indigo-400/80 uppercase tracking-wider mb-1">Thời gian ước tính</span>
                      <span className="font-medium text-white">{selectedService.estimated_duration}</span>
                    </div>
                    <div className="flex flex-col">
                      <span className="text-xs font-semibold text-indigo-400/80 uppercase tracking-wider mb-1">SLA</span>
                      <span className="font-medium text-white">{selectedService.sla_hours}h</span>
                    </div>
                  </div>
                </div>

                {/* Priority */}
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-2">
                    Mức độ ưu tiên <span className="text-rose-500">*</span>
                  </label>
                  <select
                    value={requestForm.priority}
                    onChange={(e) => setRequestForm({ ...requestForm, priority: e.target.value })}
                    className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white"
                  >
                    <option value="low">Thấp</option>
                    <option value="medium">Trung bình</option>
                    <option value="high">Cao</option>
                    <option value="urgent">Khẩn cấp</option>
                  </select>
                </div>

                {/* Request Reason */}
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-2">
                    Lý do yêu cầu <span className="text-rose-500">*</span>
                  </label>
                  <textarea
                    value={requestForm.request_reason}
                    onChange={(e) => setRequestForm({ ...requestForm, request_reason: e.target.value })}
                    rows={3}
                    placeholder="Mô tả lý do cần dịch vụ này..."
                    className="w-full px-4 py-3 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white placeholder-gray-500 resize-none"
                  />
                </div>

                {/* Evidence Summary */}
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-2">
                    Tóm tắt bằng chứng
                  </label>
                  <textarea
                    value={requestForm.evidence_summary}
                    onChange={(e) => setRequestForm({ ...requestForm, evidence_summary: e.target.value })}
                    rows={3}
                    placeholder="Tóm tắt các bằng chứng, mentions, alerts liên quan..."
                    className="w-full px-4 py-3 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white placeholder-gray-500 resize-none"
                  />
                </div>

                {/* Desired Outcome */}
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-2">
                    Kết quả mong muốn <span className="text-rose-500">*</span>
                  </label>
                  <textarea
                    value={requestForm.desired_outcome}
                    onChange={(e) => setRequestForm({ ...requestForm, desired_outcome: e.target.value })}
                    rows={3}
                    placeholder="Mô tả kết quả mong muốn từ dịch vụ này..."
                    className="w-full px-4 py-3 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white placeholder-gray-500 resize-none"
                  />
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {/* Quoted Price */}
                  <div>
                    <label className="block text-sm font-medium text-gray-300 mb-2">
                      Giá báo (VND)
                    </label>
                    <input
                      type="number"
                      value={requestForm.quoted_price}
                      onChange={(e) => setRequestForm({ ...requestForm, quoted_price: parseFloat(e.target.value) })}
                      className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white"
                    />
                  </div>

                  {/* Deadline */}
                  <div>
                    <label className="block text-sm font-medium text-gray-300 mb-2">
                      Thời hạn
                    </label>
                    <input
                      type="datetime-local"
                      value={requestForm.deadline}
                      onChange={(e) => setRequestForm({ ...requestForm, deadline: e.target.value })}
                      className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white"
                    />
                  </div>
                </div>

                {/* Compliance Notice */}
                <div className="bg-amber-500/10 border border-amber-500/20 rounded-xl p-4">
                  <div className="flex items-start space-x-3">
                    <AlertTriangle className="w-5 h-5 text-amber-500 mt-0.5 flex-shrink-0" />
                    <div className="text-sm text-amber-200/80">
                      <strong className="text-amber-400">Lưu ý:</strong> Yêu cầu này sẽ được xem xét và phê duyệt trước khi thực hiện. 
                      Tất cả dịch vụ phải tuân thủ pháp luật và chính sách nền tảng.
                    </div>
                  </div>
                </div>
              </div>

              <div className="p-6 border-t border-gray-800 bg-[#1E293B]/30 flex justify-end space-x-3 shrink-0">
                <button
                  onClick={() => setShowCreateRequest(false)}
                  className="px-5 py-2.5 text-gray-300 bg-[#111827] border border-gray-700 rounded-xl hover:bg-gray-800 hover:text-white transition-colors font-medium"
                >
                  Hủy
                </button>
                <button
                  onClick={handleSubmitRequest}
                  disabled={!requestForm.request_reason || !requestForm.desired_outcome}
                  className="px-5 py-2.5 text-white bg-indigo-600 rounded-xl hover:bg-indigo-700 transition-colors disabled:bg-gray-800 disabled:text-gray-500 disabled:cursor-not-allowed font-medium shadow-sm shadow-indigo-500/20"
                >
                  Tạo yêu cầu
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

frontend/src/app/dashboard/settings/APIW:
'use client';

import { useState, useEffect } from 'react';
import { Key, Plus, Copy, Eye, EyeOff, Trash2, Power, PowerOff, Calendar } from 'lucide-react';
import { toast } from 'react-hot-toast';
import { api } from '@/lib/api';

interface APIKey {
  id: number;
  name: string;
  prefix: string;
  permissions: string[];
  is_active: boolean;
  expires_at: string | null;
  last_used_at: string | null;
  created_at: string;
}

interface APIKeyCreateResponse extends APIKey {
  full_key: string;
}

export default function APIWebhooks() {
  const [apiKeys, setApiKeys] = useState<APIKey[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [newKeyData, setNewKeyData] = useState({
    name: '',
    permissions: [] as string[],
    expires_at: ''
  });
  const [createdKey, setCreatedKey] = useState<string | null>(null);
  const [availablePermissions] = useState([
    'mentions.read', 'mentions.write',
    'keywords.read', 'keywords.write',
    'sources.read', 'sources.write',
    'reports.read', 'alerts.read'
  ]);

  useEffect(() => {
    loadAPIKeys();
  }, []);

  const loadAPIKeys = async () => {
    try {
      const response = await api.get('/api/api-keys/');
      setApiKeys(response.data);
    } catch (error) {
      console.error('Error loading API keys:', error);
      toast.error('Không thể tải danh sách API keys');
    } finally {
      setLoading(false);
    }
  };

  const handleCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    
    try {
      const payload = {
        name: newKeyData.name,
        permissions: newKeyData.permissions,
        expires_at: newKeyData.expires_at || null
      };

      const response = await api.post('/api/api-keys/', payload);
      const data: APIKeyCreateResponse = response.data;
      setCreatedKey(data.full_key);
      toast.success('Tạo API key thành công');
      loadAPIKeys();
    } catch (error: any) {
      console.error('Error creating API key:', error);
      toast.error(error.response?.data?.detail || 'Không thể tạo API key');
    }
  };

  const handleRevoke = async (keyId: number) => {
    if (!confirm('Bạn có chắc muốn thu hồi API key này? Hành động này không thể hoàn tác.')) return;

    try {
      await api.delete(`/api/api-keys/${keyId}`);
      toast.success('Thu hồi API key thành công');
      loadAPIKeys();
    } catch (error) {
      console.error('Error revoking API key:', error);
      toast.error('Không thể thu hồi API key');
    }
  };

  const handleToggleActive = async (keyId: number, currentStatus: boolean) => {
    try {
      const action = currentStatus ? 'deactivate' : 'activate';
      await api.post(`/api/api-keys/${keyId}/${action}`);
      toast.success(currentStatus ? 'Vô hiệu hóa thành công' : 'Kích hoạt thành công');
      loadAPIKeys();
    } catch (error) {
      console.error('Error toggling API key:', error);
      toast.error('Không thể thay đổi trạng thái');
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    toast.success('Đã sao chép vào clipboard');
  };

  const formatDate = (dateString: string | null) => {
    if (!dateString) return 'Không giới hạn';
    return new Date(dateString).toLocaleDateString('vi-VN');
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-500"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-xl font-bold text-white tracking-wide">API Keys & Webhooks</h2>
          <p className="text-sm text-gray-400 mt-1">Quản lý API keys để truy cập programmatic</p>
        </div>
        <button 
          onClick={() => {
            setShowModal(true);
            setCreatedKey(null);
            setNewKeyData({ name: '', permissions: [], expires_at: '' });
          }}
          className="flex items-center px-6 py-2.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-colors shadow-sm shadow-indigo-500/20 font-medium"
        >
          <Plus className="w-5 h-5 mr-2" />
          Tạo API Key
        </button>
      </div>

      {/* API Keys List */}
      <div className="space-y-4">
        {apiKeys.length === 0 ? (
          <div className="text-center py-12 bg-[#111827] border border-gray-800 rounded-xl shadow-sm">
            <Key className="w-12 h-12 mx-auto text-gray-500 mb-3" />
            <p className="text-gray-300 font-medium tracking-wide">Chưa có API key nào</p>
            <p className="text-sm text-gray-400 mt-1">Tạo API key để truy cập hệ thống qua API</p>
          </div>
        ) : (
          apiKeys.map((key) => (
            <div key={key.id} className={`bg-[#111827] border border-gray-800 rounded-xl p-5 shadow-sm transition-opacity ${!key.is_active ? 'opacity-50' : ''}`}>
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <div className="flex items-center space-x-3 mb-3">
                    <div className="p-2 bg-indigo-500/10 border border-indigo-500/20 rounded-lg">
                      <Key className="w-4 h-4 text-indigo-400" />
                    </div>
                    <h3 className="font-bold text-white tracking-wide">{key.name}</h3>
                    {!key.is_active && (
                      <span className="px-2.5 py-1 text-xs font-medium bg-gray-800 text-gray-400 border border-gray-700 rounded-md">
                        Vô hiệu hóa
                      </span>
                    )}
                  </div>
                  
                  <div className="flex items-center space-x-3 mb-4">
                    <code className="px-4 py-1.5 bg-[#1E293B] border border-gray-700 text-gray-300 rounded-lg text-sm font-mono tracking-wider">
                      {key.prefix}••••••••
                    </code>
                    <button
                      onClick={() => copyToClipboard(key.prefix)}
                      className="p-1.5 text-gray-400 hover:text-indigo-400 hover:bg-indigo-500/10 rounded-lg transition-colors"
                      title="Sao chép prefix"
                    >
                      <Copy className="w-4 h-4" />
                    </button>
                  </div>

                  <div className="flex flex-wrap gap-5 text-xs text-gray-400 font-medium">
                    <span className="flex items-center">
                      <Calendar className="w-3.5 h-3.5 mr-1.5 text-gray-500" />
                      Tạo: {formatDate(key.created_at)}
                    </span>
                    {key.expires_at && (
                      <span className="flex items-center text-amber-500/80">
                        <Calendar className="w-3.5 h-3.5 mr-1.5" />
                        Hết hạn: {formatDate(key.expires_at)}
                      </span>
                    )}
                    {key.last_used_at && (
                      <span className="flex items-center text-indigo-400/80">
                        <Eye className="w-3.5 h-3.5 mr-1.5" />
                        Dùng lần cuối: {formatDate(key.last_used_at)}
                      </span>
                    )}
                  </div>

                  <div className="mt-4 pt-4 border-t border-gray-800/50">
                    <p className="text-xs font-medium text-gray-400 mb-2.5">Quyền hạn ({key.permissions.length}):</p>
                    <div className="flex flex-wrap gap-2">
                      {key.permissions.slice(0, 5).map((perm, idx) => (
                        <span key={idx} className="px-2.5 py-1 text-[11px] font-medium bg-indigo-500/10 text-indigo-400 border border-indigo-500/20 rounded-md uppercase tracking-wider">
                          {perm}
                        </span>
                      ))}
                      {key.permissions.length > 5 && (
                        <span className="px-2.5 py-1 text-[11px] font-medium bg-[#1E293B] text-gray-400 border border-gray-700 rounded-md">
                          +{key.permissions.length - 5}
                        </span>
                      )}
                    </div>
                  </div>
                </div>

                <div className="flex space-x-2 ml-4">
                  <button
                    onClick={() => handleToggleActive(key.id, key.is_active)}
                    className={`p-2 rounded-lg transition-colors ${key.is_active ? 'text-amber-500 hover:bg-amber-500/10' : 'text-emerald-500 hover:bg-emerald-500/10'}`}
                    title={key.is_active ? 'Vô hiệu hóa' : 'Kích hoạt'}
                  >
                    {key.is_active ? <PowerOff className="w-4 h-4" /> : <Power className="w-4 h-4" />}
                  </button>
                  <button
                    onClick={() => handleRevoke(key.id)}
                    className="p-2 text-rose-500 hover:bg-rose-500/10 rounded-lg transition-colors"
                    title="Thu hồi"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      {/* Create Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-[60] p-4">
          <div className="bg-[#111827] border border-gray-800 rounded-2xl shadow-2xl max-w-lg w-full">
            <div className="p-6 border-b border-gray-800">
              <h3 className="text-lg font-bold text-white tracking-wide">
                {createdKey ? 'API Key đã tạo' : 'Tạo API Key mới'}
              </h3>
            </div>

            {createdKey ? (
              <div className="p-6 space-y-6">
                <div className="bg-amber-500/10 border border-amber-500/20 rounded-xl p-5">
                  <p className="text-sm text-amber-400 font-bold tracking-wide mb-2 flex items-center">
                    <span className="mr-2">⚠️</span> Lưu ý quan trọng
                  </p>
                  <p className="text-sm text-amber-200">
                    Đây là lần duy nhất bạn có thể xem API key đầy đủ. Hãy sao chép và lưu trữ an toàn.
                  </p>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-3">
                    API Key của bạn:
                  </label>
                  <div className="flex items-center space-x-3">
                    <code className="flex-1 px-4 py-3 bg-[#1E293B] border border-indigo-500/30 text-indigo-300 rounded-xl text-sm font-mono break-all tracking-wider">
                      {createdKey}
                    </code>
                    <button
                      onClick={() => copyToClipboard(createdKey)}
                      className="p-3 text-indigo-400 hover:bg-indigo-500/10 rounded-xl transition-colors border border-transparent hover:border-indigo-500/20"
                      title="Sao chép"
                    >
                      <Copy className="w-5 h-5" />
                    </button>
                  </div>
                </div>

                <div className="flex justify-end pt-4">
                  <button
                    onClick={() => {
                      setShowModal(false);
                      setCreatedKey(null);
                    }}
                    className="px-6 py-2.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-colors shadow-sm shadow-indigo-500/20 font-medium"
                  >
                    Đóng
                  </button>
                </div>
              </div>
            ) : (
              <form onSubmit={handleCreate} className="p-6 space-y-5">
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-2">
                    Tên API Key <span className="text-rose-500">*</span>
                  </label>
                  <input
                    type="text"
                    value={newKeyData.name}
                    onChange={(e) => setNewKeyData({ ...newKeyData, name: e.target.value })}
                    className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:outline-none text-white placeholder-gray-500"
                    placeholder="e.g., Production API Key"
                    required
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-2">
                    Quyền hạn
                  </label>
                  <div className="border border-gray-800 bg-[#1E293B] rounded-xl p-4 max-h-48 overflow-y-auto">
                    <div className="grid grid-cols-2 gap-3">
                      {availablePermissions.map((perm) => (
                        <label key={perm} className="flex items-center space-x-3 cursor-pointer group p-1.5 hover:bg-gray-800 rounded-lg transition-colors">
                          <input
                            type="checkbox"
                            checked={newKeyData.permissions.includes(perm)}
                            onChange={(e) => {
                              if (e.target.checked) {
                                setNewKeyData({ ...newKeyData, permissions: [...newKeyData.permissions, perm] });
                              } else {
                                setNewKeyData({ ...newKeyData, permissions: newKeyData.permissions.filter(p => p !== perm) });
                              }
                            }}
                            className="w-4 h-4 rounded bg-[#111827] border-gray-600 text-indigo-600 focus:ring-indigo-500 focus:ring-offset-gray-900"
                          />
                          <span className="text-sm font-medium text-gray-300 group-hover:text-white transition-colors">{perm}</span>
                        </label>
                      ))}
                    </div>
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-2">
                    Ngày hết hạn (tùy chọn)
                  </label>
                  <input
                    type="datetime-local"
                    value={newKeyData.expires_at}
                    onChange={(e) => setNewKeyData({ ...newKeyData, expires_at: e.target.value })}
                    className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:outline-none text-white [color-scheme:dark]"
                  />
                </div>

                <div className="flex justify-end space-x-3 pt-6 border-t border-gray-800">
                  <button
                    type="button"
                    onClick={() => setShowModal(false)}
                    className="px-6 py-2.5 bg-[#1E293B] text-gray-300 border border-gray-700 rounded-xl hover:bg-gray-800 transition-colors font-medium"
                  >
                    Hủy
                  </button>
                  <button
                    type="submit"
                    className="px-6 py-2.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-colors shadow-sm shadow-indigo-500/20 font-medium"
                  >
                    Tạo API Key
                  </button>
                </div>
              </form>
            )}
          </div>
        </div>
      )}

      {/* Info Box */}
      <div className="bg-indigo-500/10 border border-indigo-500/20 rounded-xl p-4">
        <p className="text-sm text-indigo-200">
          <strong className="text-indigo-300">Lưu ý:</strong> API keys cho phép truy cập programmatic vào hệ thống. 
          Hãy giữ chúng an toàn và không chia sẻ công khai. Bạn có thể tạo tối đa 10 API keys đang hoạt động.
        </p>
      </div>
    </div>
  );
}

frontend/src/app/dashboard/settings/Appe:
'use client';

import { useState, useEffect } from 'react';
import { Palette, Save } from 'lucide-react';
import toast from 'react-hot-toast';

export default function AppearanceSettings() {
  const [settings, setSettings] = useState({
    theme: 'system',
    language: 'vi',
    sidebarCollapsed: false,
    itemsPerPage: 20
  });
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    loadSettings();
  }, []);

  const loadSettings = async () => {
    try {
      const token=***REDACTED***'access_token');
      const response = await fetch('https://social-listening-backend.onrender.com/api/auth/me/preferences', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });

      if (response.ok) {
        const data = await response.json();
        const newSettings = {
          theme: data.theme,
          language: data.language,
          sidebarCollapsed: data.sidebar_collapsed,
          itemsPerPage: data.items_per_page
        };
        setSettings(newSettings);
        // Apply theme immediately
        applyTheme(data.theme);
      }
    } catch (error) {
      console.error('Failed to load preferences:', error);
      toast.error('Không thể tải cài đặt giao diện');
    } finally {
      setLoading(false);
    }
  };

  const applyTheme = (theme: string) => {
    // Apply theme to document
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else if (theme === 'light') {
      document.documentElement.classList.remove('dark');
    } else {
      // System theme
      if (window.matchMedia('(prefers-color-scheme: dark)').matches) {
        document.documentElement.classList.add('dark');
      } else {
        document.documentElement.classList.remove('dark');
      }
    }
  };

  const handleSave = async () => {
    console.log('🔵 [AppearanceSettings] handleSave called');
    console.log('🔵 [AppearanceSettings] Current settings:', settings);
    
    setSaving(true);
    try {
      const token=***REDACTED***'access_token');
      console.log('🔵 [AppearanceSettings] Token:', token ? 'exists' : 'missing');
      
      const payload = {
        theme: settings.theme,
        language: settings.language,
        sidebar_collapsed: settings.sidebarCollapsed,
        items_per_page: settings.itemsPerPage
      };
      console.log('🔵 [AppearanceSettings] Payload:', payload);
      
      const response = await fetch('https://social-listening-backend.onrender.com/api/auth/me/preferences', {
        method: 'PUT',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(payload)
      });

      console.log('🔵 [AppearanceSettings] Response status:', response.status);

      if (response.ok) {
        const data = await response.json();
        console.log('✅ [AppearanceSettings] Success:', data);
        // Apply theme immediately
        applyTheme(settings.theme);
        toast.success('✅ Đã lưu cài đặt giao diện');
      } else {
        const error = await response.json();
        console.error('❌ [AppearanceSettings] Error:', error);
        toast.error(error.detail || 'Không thể lưu cài đặt');
      }
    } catch (error) {
      console.error('❌ [AppearanceSettings] Exception:', error);
      toast.error('Không thể lưu cài đặt giao diện');
    } finally {
      setSaving(false);
      console.log('🔵 [AppearanceSettings] handleSave finished');
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <h2 className="text-xl font-semibold text-gray-900">Giao diện</h2>
        <p className="text-sm text-gray-600 mt-1">Tùy chỉnh giao diện ứng dụng</p>
      </div>

      {/* Appearance Settings */}
      <div className="bg-white border border-gray-200 rounded-lg p-6 space-y-6">
        {/* Theme */}
        <div>
          <label className="block text-sm font-medium text-gray-900 mb-3">
            Chủ đề
          </label>
          <div className="grid grid-cols-3 gap-3">
            {[
              { value: 'light', label: 'Sáng', icon: '☀️' },
              { value: 'dark', label: 'Tối', icon: '🌙' },
              { value: 'system', label: 'Hệ thống', icon: '💻' }
            ].map((theme) => (
              <button
                key={theme.value}
                onClick={() => {
                  console.log(`🔴 THEME BUTTON CLICKED - ${theme.value}`);
                  console.log(`🔵 [AppearanceSettings] Theme changed to:`, theme.value);
                  setSettings({ ...settings, theme: theme.value });
                  // Apply theme immediately
                  applyTheme(theme.value);
                }}
                className={`p-4 border-2 rounded-lg transition-colors ${
                  settings.theme === theme.value
                    ? 'border-blue-600 bg-blue-50'
                    : 'border-gray-200 hover:border-gray-300'
                }`}
              >
                <div className="text-2xl mb-2">{theme.icon}</div>
                <div className="text-sm font-medium text-gray-900">{theme.label}</div>
              </button>
            ))}
          </div>
        </div>

        {/* Language */}
        <div>
          <label className="block text-sm font-medium text-gray-900 mb-2">
            Ngôn ngữ
          </label>
          <select
            value={settings.language}
            onChange={(e) => setSettings({ ...settings, language: e.target.value })}
            className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <option value="vi">Tiếng Việt</option>
            <option value="en">English</option>
          </select>
        </div>

        {/* Items per page */}
        <div>
          <label className="block text-sm font-medium text-gray-900 mb-2">
            Số mục mỗi trang
          </label>
          <select
            value={settings.itemsPerPage}
            onChange={(e) => setSettings({ ...settings, itemsPerPage: parseInt(e.target.value) })}
            className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <option value="10">10</option>
            <option value="20">20</option>
            <option value="50">50</option>
            <option value="100">100</option>
          </select>
        </div>

        {/* Sidebar Collapsed */}
        <div className="flex items-center justify-between py-3 border-t border-gray-100">
          <div>
            <p className="text-sm font-medium text-gray-900">Thu gọn sidebar</p>
            <p className="text-xs text-gray-500 mt-1">Sidebar sẽ thu gọn mặc định</p>
          </div>
          <label className="relative inline-flex items-center cursor-pointer">
            <input
              type="checkbox"
              checked={settings.sidebarCollapsed}
              onChange={(e) => setSettings({ ...settings, sidebarCollapsed: e.target.checked })}
              className="sr-only peer"
            />
            <div className="w-11 h-6 bg-gray-200 peer-focus:outline-none peer-focus:ring-4 peer-focus:ring-blue-300 rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-blue-600"></div>
          </label>
        </div>

        <div className="flex justify-end pt-4">
          <button
            onClick={() => {
              console.log('🔴 SAVE BUTTON CLICKED');
              console.log('🔴 Current settings:', settings);
              handleSave();
            }}
            disabled={saving}
            className="flex items-center px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
          >
            <Save className="w-4 h-4 mr-2" />
            {saving ? 'Đang lưu...' : 'Lưu cài đặt'}
          </button>
        </div>
      </div>
    </div>
  );
}

frontend/src/app/dashboard/settings/Audi:
'use client';

import { useState, useEffect } from 'react';
import { FileText, Search, Filter, Download, Calendar, User, Activity } from 'lucide-react';
import { toast } from 'react-hot-toast';

interface AuditLog {
  id: number;
  user_id: number | null;
  action: string;
  resource_type: string | null;
  resource_id: number | null;
  details: any;
  ip_address: string | null;
  user_agent: string | null;
  created_at: string;
}

interface FilterParams {
  user_id: string;
  action: string;
  resource_type: string;
  start_date: string;
  end_date: string;
  limit: number;
  offset: number;
}

export default function AuditLogs() {
  const [logs, setLogs] = useState<AuditLog[]>([]);
  const [loading, setLoading] = useState(true);
  const [showFilters, setShowFilters] = useState(false);
  const [filters, setFilters] = useState<FilterParams>({
    user_id: '',
    action: '',
    resource_type: '',
    start_date: '',
    end_date: '',
    limit: 100,
    offset: 0
  });
  const [stats, setStats] = useState<any>(null);

  useEffect(() => {
    loadLogs();
    loadStats();
  }, []);

  const loadLogs = async () => {
    try {
      const token=***REDACTED***'access_token');
      
      // Build query params
      const params = new URLSearchParams();
      if (filters.user_id) params.append('user_id', filters.user_id);
      if (filters.action) params.append('action', filters.action);
      if (filters.resource_type) params.append('resource_type', filters.resource_type);
      if (filters.start_date) params.append('start_date', filters.start_date);
      if (filters.end_date) params.append('end_date', filters.end_date);
      params.append('limit', filters.limit.toString());
      params.append('offset', filters.offset.toString());

      const response = await fetch(`https://social-listening-backend.onrender.com/api/admin/audit/?${params}`, {
        headers: { 'Authorization': `Bearer ${token}` }
      });

      if (!response.ok) throw new Error('Failed to load audit logs');
      
      const data = await response.json();
      setLogs(data);
    } catch (error) {
      console.error('Error loading audit logs:', error);
      toast.error('Không thể tải audit logs');
    } finally {
      setLoading(false);
    }
  };

  const loadStats = async () => {
    try {
      const token=***REDACTED***'access_token');
      const response = await fetch('https://social-listening-backend.onrender.com/api/admin/audit/stats/summary', {
        headers: { 'Authorization': `Bearer ${token}` }
      });

      if (!response.ok) throw new Error('Failed to load stats');
      
      const data = await response.json();
      setStats(data);
    } catch (error) {
      console.error('Error loading stats:', error);
    }
  };

  const handleSearch = () => {
    setLoading(true);
    loadLogs();
  };

  const handleReset = () => {
    setFilters({
      user_id: '',
      action: '',
      resource_type: '',
      start_date: '',
      end_date: '',
      limit: 100,
      offset: 0
    });
    setTimeout(() => {
      setLoading(true);
      loadLogs();
    }, 100);
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleString('vi-VN');
  };

  const getActionColor = (action: string) => {
    if (action.includes('create')) return 'text-emerald-400 bg-emerald-500/10 border border-emerald-500/20';
    if (action.includes('update')) return 'text-blue-400 bg-blue-500/10 border border-blue-500/20';
    if (action.includes('delete')) return 'text-rose-400 bg-rose-500/10 border border-rose-500/20';
    return 'text-gray-400 bg-gray-800 border border-gray-700';
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-500"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-xl font-bold text-white tracking-wide">Audit Logs</h2>
          <p className="text-sm text-gray-400 mt-1">Lịch sử hoạt động và thay đổi trong hệ thống</p>
        </div>
        <button
          onClick={() => setShowFilters(!showFilters)}
          className="flex items-center px-4 py-2.5 text-gray-300 bg-[#1E293B] border border-gray-700 rounded-xl hover:bg-gray-800 transition-colors font-medium"
        >
          <Filter className="w-4 h-4 mr-2" />
          {showFilters ? 'Ẩn bộ lọc' : 'Hiện bộ lọc'}
        </button>
      </div>

      {/* Stats */}
      {stats && (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="bg-[#111827] border border-gray-800 rounded-xl p-6 shadow-sm">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-gray-400">Tổng số logs</p>
                <p className="text-2xl font-bold text-white tracking-wide mt-1">{stats.total_logs}</p>
              </div>
              <div className="p-3 bg-indigo-500/10 border border-indigo-500/20 rounded-xl">
                <Activity className="w-6 h-6 text-indigo-400" />
              </div>
            </div>
          </div>

          <div className="bg-[#111827] border border-gray-800 rounded-xl p-6 shadow-sm">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-gray-400">Loại hành động</p>
                <p className="text-2xl font-bold text-white tracking-wide mt-1">{stats.by_action?.length || 0}</p>
              </div>
              <div className="p-3 bg-emerald-500/10 border border-emerald-500/20 rounded-xl">
                <FileText className="w-6 h-6 text-emerald-400" />
              </div>
            </div>
          </div>

          <div className="bg-[#111827] border border-gray-800 rounded-xl p-6 shadow-sm">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm font-medium text-gray-400">Hiển thị</p>
                <p className="text-2xl font-bold text-white tracking-wide mt-1">{logs.length}</p>
              </div>
              <div className="p-3 bg-purple-500/10 border border-purple-500/20 rounded-xl">
                <Search className="w-6 h-6 text-purple-400" />
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Filters */}
      {showFilters && (
        <div className="bg-[#111827] border border-gray-800 rounded-xl p-6 shadow-sm">
          <h3 className="text-lg font-bold text-white tracking-wide mb-6">Bộ lọc</h3>
          
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">User ID</label>
              <input
                type="number"
                value={filters.user_id}
                onChange={(e) => setFilters({ ...filters, user_id: e.target.value })}
                className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white placeholder-gray-500 transition-shadow"
                placeholder="ID người dùng"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">Hành động</label>
              <input
                type="text"
                value={filters.action}
                onChange={(e) => setFilters({ ...filters, action: e.target.value })}
                className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white placeholder-gray-500 transition-shadow"
                placeholder="e.g., user.create"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">Loại tài nguyên</label>
              <input
                type="text"
                value={filters.resource_type}
                onChange={(e) => setFilters({ ...filters, resource_type: e.target.value })}
                className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white placeholder-gray-500 transition-shadow"
                placeholder="e.g., user, source"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">Từ ngày</label>
              <input
                type="datetime-local"
                value={filters.start_date}
                onChange={(e) => setFilters({ ...filters, start_date: e.target.value })}
                className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white [color-scheme:dark] transition-shadow"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">Đến ngày</label>
              <input
                type="datetime-local"
                value={filters.end_date}
                onChange={(e) => setFilters({ ...filters, end_date: e.target.value })}
                className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white [color-scheme:dark] transition-shadow"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">Số lượng</label>
              <select
                value={filters.limit}
                onChange={(e) => setFilters({ ...filters, limit: parseInt(e.target.value) })}
                className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white [color-scheme:dark] transition-shadow"
              >
                <option value={50}>50</option>
                <option value={100}>100</option>
                <option value={200}>200</option>
                <option value={500}>500</option>
              </select>
            </div>
          </div>

          <div className="flex justify-end space-x-3 mt-8 pt-6 border-t border-gray-800">
            <button
              onClick={handleReset}
              className="px-6 py-2.5 text-gray-300 bg-[#1E293B] border border-gray-700 rounded-xl hover:bg-gray-800 transition-colors font-medium"
            >
              Đặt lại
            </button>
            <button
              onClick={handleSearch}
              className="flex items-center px-6 py-2.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-colors font-medium shadow-sm shadow-indigo-500/20"
            >
              <Search className="w-4 h-4 mr-2" />
              Tìm kiếm
            </button>
          </div>
        </div>
      )}

      {/* Logs Table */}
      <div className="bg-[#111827] border border-gray-800 rounded-xl overflow-hidden shadow-sm">
        {logs.length === 0 ? (
          <div className="text-center py-12">
            <FileText className="w-12 h-12 mx-auto text-gray-600 mb-3" />
            <p className="text-gray-400 font-medium tracking-wide">Không có audit logs</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead className="bg-[#1E293B]/50 border-b border-gray-800">
                <tr>
                  <th className="px-6 py-4 text-left text-xs font-semibold text-gray-400 uppercase tracking-wider">Thời gian</th>
                  <th className="px-6 py-4 text-left text-xs font-semibold text-gray-400 uppercase tracking-wider">User</th>
                  <th className="px-6 py-4 text-left text-xs font-semibold text-gray-400 uppercase tracking-wider">Hành động</th>
                  <th className="px-6 py-4 text-left text-xs font-semibold text-gray-400 uppercase tracking-wider">Tài nguyên</th>
                  <th className="px-6 py-4 text-left text-xs font-semibold text-gray-400 uppercase tracking-wider">IP</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-800/50">
                {logs.map((log) => (
                  <tr key={log.id} className="hover:bg-[#1E293B]/50 transition-colors">
                    <td className="px-6 py-4 text-sm text-gray-200 font-medium whitespace-nowrap">
                      {formatDate(log.created_at)}
                    </td>
                    <td className="px-6 py-4 text-sm text-gray-400">
                      {log.user_id ? (
                        <span className="flex items-center text-gray-300">
                          <User className="w-4 h-4 mr-2 text-indigo-400" />
                          ID: {log.user_id}
                        </span>
                      ) : (
                        <span className="text-gray-500 font-medium">System</span>
                      )}
                    </td>
                    <td className="px-6 py-4">
                      <span className={`inline-block px-2.5 py-1 text-xs font-medium rounded-md tracking-wide ${getActionColor(log.action)}`}>
                        {log.action}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-sm text-gray-400 font-medium">
                      {log.resource_type && (
                        <span>
                          {log.resource_type}
                          {log.resource_id && <span className="text-gray-500 ml-1">#{log.resource_id}</span>}
                        </span>
                      )}
                    </td>
                    <td className="px-6 py-4 text-sm text-gray-500 font-mono tracking-wider">
                      {log.ip_address || '-'}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Pagination */}
      {logs.length > 0 && (
        <div className="flex items-center justify-between">
          <p className="text-sm font-medium text-gray-400">
            Hiển thị <span className="text-white">{filters.offset + 1} - {filters.offset + logs.length}</span> logs
          </p>
          <div className="flex space-x-3">
            <button
              onClick={() => {
                setFilters({ ...filters, offset: Math.max(0, filters.offset - filters.limit) });
                setTimeout(loadLogs, 100);
              }}
              disabled={filters.offset === 0}
              className="px-5 py-2.5 text-gray-300 bg-[#1E293B] border border-gray-700 rounded-xl hover:bg-gray-800 transition-colors font-medium disabled:opacity-50 disabled:cursor-not-allowed"
            >
              Trước
            </button>
            <button
              onClick={() => {
                setFilters({ ...filters, offset: filters.offset + filters.limit });
                setTimeout(loadLogs, 100);
              }}
              disabled={logs.length < filters.limit}
              className="px-5 py-2.5 text-gray-300 bg-[#1E293B] border border-gray-700 rounded-xl hover:bg-gray-800 transition-colors font-medium disabled:opacity-50 disabled:cursor-not-allowed"
            >
              Sau
            </button>
          </div>
        </div>
      )}

      {/* Info Box */}
      <div className="bg-indigo-500/10 border border-indigo-500/20 rounded-xl p-4">
        <p className="text-sm text-indigo-200">
          <strong className="text-indigo-300">Lưu ý:</strong> Audit logs ghi lại tất cả hoạt động quan trọng trong hệ thống. 
          Dữ liệu này được lưu trữ vĩnh viễn để đảm bảo tính minh bạch và truy vết.
        </p>
      </div>
    </div>
  );
}

