'use client';

import { useState, useEffect } from 'react';
import { Mail, Save, Send } from 'lucide-react';
import toast from 'react-hot-toast';

export default function EmailSettings() {
  const [settings, setSettings] = useState({
    smtpHost: '',
    smtpPort: 587,
    smtpUsername: '',
    smtpPassword: '',
    fromEmail: '',
    fromName: '',
    useTls: true,
    useSsl: false
  });
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [testing, setTesting] = useState(false);
  const [isConfigured, setIsConfigured] = useState(false);

  useEffect(() => {
    loadSettings();
  }, []);

  const loadSettings = async () => {
    try {
      const token=***REDACTED***'access_token');
      const response = await fetch('https://social-listening-backend.onrender.com/api/admin/settings/email', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });

      if (response.ok) {
        const data = await response.json();
        setSettings({
          smtpHost: data.smtp_host || '',
          smtpPort: data.smtp_port || 587,
          smtpUsername: data.smtp_username || '',
          smtpPassword: '', // Never load password from backend
          fromEmail: data.from_email || '',
          fromName: data.from_name || '',
          useTls: data.use_tls !== undefined ? data.use_tls : true,
          useSsl: data.use_ssl !== undefined ? data.use_ssl : false
        });
        setIsConfigured(data.is_configured || false);
      }
    } catch (error) {
      console.error('Failed to load email settings:', error);
      toast.error('Không thể tải cấu hình email');
    } finally {
      setLoading(false);
    }
  };

  const handleSave = async () => {
    if (!settings.smtpHost || !settings.smtpUsername || !settings.fromEmail) {
      toast.error('Vui lòng điền đầy đủ thông tin bắt buộc');
      return;
    }

    setSaving(true);
    try {
      const token=***REDACTED***'access_token');
      const payload: any = {
        smtp_host: settings.smtpHost,
        smtp_port: settings.smtpPort,
        smtp_username: settings.smtpUsername,
        from_email: settings.fromEmail,
        from_name: settings.fromName,
        use_tls: settings.useTls,
        use_ssl: settings.useSsl
      };

      // Only include password if it was changed
      if (settings.smtpPassword) {
        payload.smtp_password=***REDACTED***
      }

      const response = await fetch('https://social-listening-backend.onrender.com/api/admin/settings/email', {
        method: 'PUT',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(payload)
      });

      if (response.ok) {
        const data = await response.json();
        setIsConfigured(data.is_configured);
        toast.success('Đã lưu cấu hình email');
        // Clear password field after save
        setSettings({ ...settings, smtpPassword: '' });
      } else {
        const error = await response.json();
        toast.error(error.detail || 'Không thể lưu cấu hình');
      }
    } catch (error) {
      console.error('Failed to save email settings:', error);
      toast.error('Không thể lưu cấu hình email');
    } finally {
      setSaving(false);
    }
  };

  const handleTest = async () => {
    if (!isConfigured) {
      toast.error('Vui lòng lưu cấu hình trước khi test');
      return;
    }

    setTesting(true);
    try {
      const token=***REDACTED***'access_token');
      const response = await fetch('https://social-listening-backend.onrender.com/api/admin/settings/email/test', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });

      if (response.ok) {
        const data = await response.json();
        toast.success(data.message || 'Email test thành công');
      } else {
        const error = await response.json();
        toast.error(error.detail || 'Test email thất bại');
      }
    } catch (error) {
      console.error('Failed to test email:', error);
      toast.error('Không thể test email');
    } finally {
      setTesting(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-500"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <h2 className="text-xl font-bold text-white tracking-wide">Cấu hình Email</h2>
        <p className="text-sm text-gray-400 mt-1">Cấu hình SMTP để gửi email thông báo</p>
      </div>

      {/* Status Badge */}
      {isConfigured && (
        <div className="bg-emerald-500/10 border border-emerald-500/20 rounded-xl p-4">
          <p className="text-sm font-medium text-emerald-400 flex items-center">
            <span className="mr-2">✅</span> Email đã được cấu hình. Hệ thống có thể gửi email thông báo.
          </p>
        </div>
      )}

      {/* SMTP Settings */}
      <div className="bg-[#111827] border border-gray-800 rounded-xl shadow-sm p-6 space-y-6">
        <h3 className="text-lg font-bold text-white tracking-wide flex items-center">
          <Mail className="w-5 h-5 mr-2 text-indigo-400" />
          Cấu hình SMTP
        </h3>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <label className="block text-sm font-medium text-gray-300 mb-2">
              SMTP Host *
            </label>
            <input
              type="text"
              value={settings.smtpHost}
              onChange={(e) => setSettings({ ...settings, smtpHost: e.target.value })}
              className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white placeholder-gray-500 transition-shadow"
              placeholder="smtp.gmail.com"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-300 mb-2">
              SMTP Port *
            </label>
            <input
              type="number"
              value={settings.smtpPort}
              onChange={(e) => setSettings({ ...settings, smtpPort: parseInt(e.target.value) })}
              className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white placeholder-gray-500 transition-shadow"
              placeholder="587"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-300 mb-2">
              SMTP Username *
            </label>
            <input
              type="text"
              value={settings.smtpUsername}
              onChange={(e) => setSettings({ ...settings, smtpUsername: e.target.value })}
              className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white placeholder-gray-500 transition-shadow"
              placeholder="your-email@gmail.com"
