      console.error(`Failed to test ${channel}:`, error);
      toast.error(`Không thể test ${channel}`);
    } finally {
      setTesting(null);
    }
  };

  const toggleChannel = (channel: string) => {
    if (settings.alertChannels.includes(channel)) {
