'use client';

import { useState, useEffect } from 'react';
import { Bell, Save } from 'lucide-react';
import toast from 'react-hot-toast';

export default function PersonalNotifications() {
  const [settings, setSettings] = useState({
    emailNotifications: true,
    inAppNotifications: true,
    alertNotifications: true,
    incidentNotifications: true,
    reportNotifications: false
  });
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    loadSettings();
  }, []);

  const loadSettings = async () => {
    try {
      const token=***REDACTED***'access_token');
      const response = await fetch('https://social-listening-backend.onrender.com/api/auth/me/notification-settings', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });

      if (response.ok) {
        const data = await response.json();
        setSettings({
          emailNotifications: data.email_notifications,
          inAppNotifications: data.in_app_notifications,
          alertNotifications: data.alert_notifications,
          incidentNotifications: data.incident_notifications,
          reportNotifications: data.report_notifications
        });
      }
    } catch (error) {
      console.error('Failed to load notification settings:', error);
      toast.error('Không thể tải cài đặt thông báo');
    } finally {
      setLoading(false);
    }
  };

  const handleSave = async () => {
    console.log('🔵 [PersonalNotifications] handleSave called');
    console.log('🔵 [PersonalNotifications] Current settings:', settings);
    
    setSaving(true);
    try {
      const token=***REDACTED***'access_token');
      console.log('🔵 [PersonalNotifications] Token:', token ? 'exists' : 'missing');
      
      const payload = {
        email_notifications: settings.emailNotifications,
        in_app_notifications: settings.inAppNotifications,
        alert_notifications: settings.alertNotifications,
        incident_notifications: settings.incidentNotifications,
        report_notifications: settings.reportNotifications
      };
      console.log('🔵 [PersonalNotifications] Payload:', payload);
      
      const response = await fetch('https://social-listening-backend.onrender.com/api/auth/me/notification-settings', {
        method: 'PUT',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(payload)
      });

      console.log('🔵 [PersonalNotifications] Response status:', response.status);

      if (response.ok) {
        const data = await response.json();
        console.log('✅ [PersonalNotifications] Success:', data);
        toast.success('✅ Đã lưu cài đặt thông báo');
      } else {
        const error = await response.json();
        console.error('❌ [PersonalNotifications] Error:', error);
        toast.error(error.detail || 'Không thể lưu cài đặt');
      }
    } catch (error) {
      console.error('❌ [PersonalNotifications] Exception:', error);
      toast.error('Không thể lưu cài đặt thông báo');
    } finally {
      setSaving(false);
      console.log('🔵 [PersonalNotifications] handleSave finished');
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-500"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <h2 className="text-xl font-bold text-white tracking-wide">Thông báo cá nhân</h2>
        <p className="text-sm text-gray-400 mt-1">Quản lý thông báo bạn nhận được</p>
      </div>

      {/* Notification Settings */}
      <div className="bg-[#111827] border border-gray-800 rounded-xl shadow-sm p-6 space-y-4">
        <div className="space-y-4">
          {[
            { key: 'emailNotifications', label: 'Email notifications', description: 'Nhận thông báo qua email' },
            { key: 'inAppNotifications', label: 'In-app notifications', description: 'Hiển thị thông báo trong ứng dụng' },
            { key: 'alertNotifications', label: 'Cảnh báo', description: 'Thông báo khi có cảnh báo mới' },
            { key: 'incidentNotifications', label: 'Sự cố', description: 'Thông báo khi được gán sự cố' },
            { key: 'reportNotifications', label: 'Báo cáo', description: 'Nhận báo cáo định kỳ' }
          ].map((item) => (
            <div key={item.key} className="flex items-center justify-between py-3 border-b border-gray-800 last:border-0">
              <div className="flex-1">
                <p className="text-sm font-medium text-white">{item.label}</p>
                <p className="text-xs text-gray-400 mt-1">{item.description}</p>
              </div>
              <label className="relative inline-flex items-center cursor-pointer ml-4">
                <input
                  type="checkbox"
                  checked={settings[item.key as keyof typeof settings]}
                  onChange={(e) => {
                    console.log(`🔴 TOGGLE - ${item.key}:`, e.target.checked);
                    setSettings({ ...settings, [item.key]: e.target.checked });
                  }}
                  className="sr-only peer"
                />
                <div className="w-11 h-6 bg-[#1E293B] peer-focus:outline-none peer-focus:ring-2 peer-focus:ring-indigo-500/50 rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-indigo-600"></div>
              </label>
            </div>
          ))}
        </div>

        <div className="flex justify-end pt-4 border-t border-gray-800">
          <button
            onClick={() => {
              console.log('🔴 SAVE BUTTON CLICKED');
              console.log('🔴 Current settings:', settings);
              handleSave();
            }}
            disabled={saving}
            className="flex items-center px-6 py-2.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-colors disabled:bg-gray-800 disabled:text-gray-500 disabled:cursor-not-allowed shadow-sm shadow-indigo-500/20 font-medium"
          >
            <Save className="w-4 h-4 mr-2" />
            {saving ? 'Đang lưu...' : 'Lưu cài đặt'}
          </button>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect, useRef } from 'react';
import { User as UserIcon, Save, Upload } from 'lucide-react';
import { auth } from '@/lib/api';
import { getRoleDisplayName, getRoleBadgeColor } from '@/lib/permissions';
import toast from 'react-hot-toast';

export default function PersonalProfile() {
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [avatarUrl, setAvatarUrl] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  
  const [profile, setProfile] = useState({
    full_name: '',
    email: '',
    phone: '',
    department: '',
    role: ''
  });

  useEffect(() => {
    loadProfile();
  }, []);

  const loadProfile = async () => {
    try {
      const user = await auth.getCurrentUser();
      setProfile({
        full_name: user.full_name || '',
        email: user.email || '',
        phone: user.phone || '',
        department: user.department || '',
        role: user.role || 'viewer'
      });
      // Load avatar if exists
      if (user.avatar_url) {
        setAvatarUrl(user.avatar_url);
      }
    } catch (error) {
      console.error('Failed to load profile:', error);
      toast.error('Không thể tải thông tin cá nhân');
    } finally {
      setLoading(false);
    }
  };

  const handleSave = async () => {
    if (saving) return; // Prevent double-click
    
    if (!profile.full_name || profile.full_name.trim() === '') {
      toast.error('Vui lòng nhập họ và tên');
      return;
    }

    setSaving(true);
    try {
      const token=***REDACTED***'access_token');
      const response = await fetch('https://social-listening-backend.onrender.com/api/auth/me/profile', {
        method: 'PUT',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          full_name: profile.full_name.trim(),
          phone: profile.phone?.trim() || null,
          department: profile.department?.trim() || null
        })
      });

      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.detail || 'Failed to update profile');
      }

      toast.success('✅ Đã lưu thông tin cá nhân');
      await loadProfile(); // Reload to verify
    } catch (error: any) {
      console.error('Error updating profile:', error);
      toast.error(error.message || 'Lỗi khi lưu thông tin');
    } finally {
      setSaving(false);
    }
  };

  const handleUploadClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Validate file type
    if (!file.type.startsWith('image/')) {
      toast.error('Vui lòng chọn file ảnh (JPG, PNG)');
      return;
    }

    // Validate file size (2MB)
    if (file.size > 2 * 1024 * 1024) {
      toast.error('Kích thước ảnh không được vượt quá 2MB');
      return;
    }

    setUploading(true);
    try {
      // Create preview
      const reader = new FileReader();
      reader.onloadend = () => {
        setAvatarUrl(reader.result as string);
      };
      reader.readAsDataURL(file);

      // TODO: Upload to server when avatar endpoint is ready
      // For now, just show preview
      toast.success('✅ Đã tải ảnh lên (chức năng lưu ảnh đang phát triển)');
      
      // Uncomment when backend avatar endpoint is ready:
      /*
      const token=***REDACTED***'access_token');
      const formData = new FormData();
      formData.append('avatar', file);

      const response = await fetch('https://social-listening-backend.onrender.com/api/auth/me/avatar', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`
        },
        body: formData
      });

      if (!response.ok) {
        throw new Error('Failed to upload avatar');
      }

      const data = await response.json();
      setAvatarUrl(data.avatar_url);
      toast.success('✅ Đã cập nhật ảnh đại diện');
      */
    } catch (error: any) {
      console.error('Error uploading avatar:', error);
      toast.error(error.message || 'Lỗi khi tải ảnh lên');
    } finally {
      setUploading(false);
    }
  };

  if (loading) {
    return <div className="text-center py-8">Đang tải...</div>;
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <h2 className="text-xl font-bold text-white tracking-wide">Hồ sơ cá nhân</h2>
        <p className="text-sm text-gray-400 mt-1">Quản lý thông tin cá nhân của bạn</p>
      </div>

      {/* Avatar */}
      <div className="bg-[#111827] border border-gray-800 rounded-xl shadow-sm p-6">
        <div className="flex items-center space-x-6">
          <div className="w-24 h-24 bg-[#1E293B] border border-gray-700 rounded-full flex items-center justify-center overflow-hidden shadow-inner">
            {avatarUrl ? (
              <img src={avatarUrl} alt="Avatar" className="w-full h-full object-cover" />
            ) : (
              <UserIcon className="w-12 h-12 text-gray-500" />
            )}
          </div>
          <div>
            <input
              ref={fileInputRef}
              type="file"
              accept="image/jpeg,image/png,image/jpg"
              onChange={handleFileChange}
              className="hidden"
            />
            <button 
              onClick={handleUploadClick}
              disabled={uploading}
              className="flex items-center px-4 py-2.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-colors disabled:bg-gray-800 disabled:text-gray-500 disabled:cursor-not-allowed shadow-sm shadow-indigo-500/20 font-medium"
            >
              <Upload className="w-4 h-4 mr-2" />
              {uploading ? 'Đang tải...' : 'Tải ảnh lên'}
            </button>
            <p className="text-xs text-gray-500 mt-2 font-medium">JPG, PNG. Tối đa 2MB</p>
          </div>
        </div>
      </div>

      {/* Profile Form */}
      <div className="bg-[#111827] border border-gray-800 rounded-xl shadow-sm p-6 space-y-4">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div>
            <label className="block text-sm font-medium text-gray-300 mb-2">
              Họ và tên *
            </label>
            <input
              type="text"
              value={profile.full_name}
              onChange={(e) => setProfile({ ...profile, full_name: e.target.value })}
              className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white placeholder-gray-500"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-300 mb-2">
              Email
            </label>
            <input
              type="email"
              value={profile.email}
              disabled
              className="w-full px-4 py-2.5 bg-[#1E293B]/50 border border-gray-800 rounded-xl text-gray-500 cursor-not-allowed opacity-70"
            />
            <p className="text-xs text-gray-500 mt-1.5 font-medium">Email không thể thay đổi</p>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-300 mb-2">
              Số điện thoại
            </label>
            <input
              type="tel"
              value={profile.phone}
              onChange={(e) => setProfile({ ...profile, phone: e.target.value })}
              className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white placeholder-gray-500"
              placeholder="+84 xxx xxx xxx"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-300 mb-2">
              Phòng ban
            </label>
            <input
              type="text"
              value={profile.department}
              onChange={(e) => setProfile({ ...profile, department: e.target.value })}
              className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white placeholder-gray-500"
              placeholder="Ví dụ: Marketing"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-300 mb-2">
              Vai trò
            </label>
            <div className="flex items-center space-x-3 mt-1">
              <span className={`px-3 py-1 rounded-md text-xs font-bold uppercase tracking-wider ${getRoleBadgeColor(profile.role)}`}>
                {getRoleDisplayName(profile.role)}
              </span>
              <span className="text-xs font-medium text-gray-500">(Chỉ admin có thể thay đổi)</span>
            </div>
          </div>
        </div>

        <div className="flex justify-end pt-4 border-t border-gray-800">
          <button
            onClick={handleSave}
            disabled={saving}
            className="flex items-center px-6 py-2.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-colors disabled:bg-gray-800 disabled:text-gray-500 disabled:cursor-not-allowed shadow-sm shadow-indigo-500/20 font-medium"
          >
            <Save className="w-4 h-4 mr-2" />
            {saving ? 'Đang lưu...' : 'Lưu thay đổi'}
          </button>
        </div>
      </div>
    </div>
  );
}

frontend/src/app/dashboard/settings/Role:
'use client';

import { useState, useEffect } from 'react';
import { Shield, Plus, Edit2, Trash2, X, Check, Users } from 'lucide-react';
import { toast } from 'react-hot-toast';

interface Role {
  id: number;
  name: string;
  display_name: string;
  description: string | null;
  permissions: string[];
  is_system: boolean;
  is_active: boolean;
  created_at: string;
}

interface RoleFormData {
  name: string;
  display_name: string;
  description: string;
  permissions: string[];
  is_active: boolean;
}

export default function RoleManagement() {
  const [roles, setRoles] = useState<Role[]>([]);
  const [availablePermissions, setAvailablePermissions] = useState<string[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editingRole, setEditingRole] = useState<Role | null>(null);
  const [formData, setFormData] = useState<RoleFormData>({
    name: '',
    display_name: '',
    description: '',
    permissions: [],
    is_active: true
  });

  useEffect(() => {
    loadRoles();
    loadAvailablePermissions();
  }, []);

  const loadRoles = async () => {
    try {
      const token=***REDACTED***'access_token');
      const response = await fetch('https://social-listening-backend.onrender.com/api/admin/roles/', {
        headers: { 'Authorization': `Bearer ${token}` }
      });

      if (!response.ok) throw new Error('Failed to load roles');
      
      const data = await response.json();
      setRoles(data);
    } catch (error) {
      console.error('Error loading roles:', error);
      toast.error('Không thể tải danh sách vai trò');
    } finally {
      setLoading(false);
    }
  };

  const loadAvailablePermissions = async () => {
    try {
      const token=***REDACTED***'access_token');
      const response = await fetch('https://social-listening-backend.onrender.com/api/admin/roles/permissions/available', {
        headers: { 'Authorization': `Bearer ${token}` }
      });

      if (!response.ok) throw new Error('Failed to load permissions');
      
      const data = await response.json();
      setAvailablePermissions(data);
    } catch (error) {
      console.error('Error loading permissions:', error);
    }
  };

  const handleCreate = () => {
    setEditingRole(null);
    setFormData({
      name: '',
      display_name: '',
      description: '',
      permissions: [],
      is_active: true
    });
    setShowModal(true);
  };

  const handleEdit = (role: Role) => {
    setEditingRole(role);
    setFormData({
      name: role.name,
      display_name: role.display_name,
      description: role.description || '',
      permissions: role.permissions,
      is_active: role.is_active
    });
    setShowModal(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    try {
      const token=***REDACTED***'access_token');
      const url = editingRole
        ? `https://social-listening-backend.onrender.com/api/admin/roles/${editingRole.id}`
        : 'https://social-listening-backend.onrender.com/api/admin/roles/';
      
      const method = editingRole ? 'PUT' : 'POST';
      
      // For system roles, only send permissions and is_active
      const payload = editingRole?.is_system
        ? { permissions: formData.permissions, is_active: formData.is_active }
        : formData;

      const response = await fetch(url, {
        method,
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(payload)
      });

      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.detail || 'Failed to save role');
      }

      toast.success(editingRole ? 'Cập nhật vai trò thành công' : 'Tạo vai trò thành công');
      setShowModal(false);
      loadRoles();
    } catch (error: any) {
      console.error('Error saving role:', error);
      toast.error(error.message || 'Không thể lưu vai trò');
    }
  };

  const handleDelete = async (role: Role) => {
    if (!confirm(`Bạn có chắc muốn xóa vai trò "${role.display_name}"?`)) return;

    try {
      const token=***REDACTED***'access_token');
      const response = await fetch(`https://social-listening-backend.onrender.com/api/admin/roles/${role.id}`, {
        method: 'DELETE',
        headers: { 'Authorization': `Bearer ${token}` }
      });

      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.detail || 'Failed to delete role');
      }

      toast.success('Xóa vai trò thành công');
      loadRoles();
    } catch (error: any) {
      console.error('Error deleting role:', error);
      toast.error(error.message || 'Không thể xóa vai trò');
    }
  };

  const togglePermission = (permission: string) => {
    setFormData(prev => ({
      ...prev,
      permissions: prev.permissions.includes(permission)
        ? prev.permissions.filter(p => p !== permission)
        : [...prev.permissions, permission]
    }));
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-500"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-xl font-bold text-white tracking-wide">Quản lý vai trò</h2>
          <p className="text-sm text-gray-400 mt-1">Định nghĩa vai trò và quyền hạn trong hệ thống</p>
        </div>
        <button 
          onClick={handleCreate}
          className="flex items-center px-6 py-2.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-colors shadow-sm shadow-indigo-500/20 font-medium"
        >
          <Plus className="w-5 h-5 mr-2" />
          Thêm vai trò
        </button>
      </div>

      {/* Roles Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {roles.map((role) => (
          <div key={role.id} className={`bg-[#111827] border border-gray-800 rounded-xl p-6 shadow-sm hover:shadow-md transition-shadow ${!role.is_active ? 'opacity-50' : ''}`}>
            <div className="flex items-start justify-between mb-4">
              <div className="flex items-center space-x-4">
                <div className={`p-3 rounded-xl border ${role.is_system ? 'bg-purple-500/10 border-purple-500/20' : 'bg-indigo-500/10 border-indigo-500/20'}`}>
                  <Shield className={`w-6 h-6 ${role.is_system ? 'text-purple-400' : 'text-indigo-400'}`} />
                </div>
                <div>
                  <h3 className="text-lg font-bold text-white tracking-wide">{role.display_name}</h3>
                  <p className="text-xs text-gray-400 font-mono mt-0.5">{role.name}</p>
                  {role.is_system && (
                    <span className="inline-block mt-1.5 px-2 py-0.5 text-[10px] font-bold uppercase tracking-wider bg-purple-500/10 text-purple-400 border border-purple-500/20 rounded-md">
                      Hệ thống
                    </span>
                  )}
                </div>
              </div>
              <div className="flex space-x-1">
                <button 
                  onClick={() => handleEdit(role)}
                  className="p-2 text-indigo-400 hover:bg-indigo-500/10 rounded-lg transition-colors"
                  title="Chỉnh sửa"
                >
                  <Edit2 className="w-4 h-4" />
                </button>
                {!role.is_system && (
                  <button 
                    onClick={() => handleDelete(role)}
                    className="p-2 text-rose-400 hover:bg-rose-500/10 rounded-lg transition-colors"
                    title="Xóa"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                )}
              </div>
            </div>

            {role.description && (
              <p className="text-sm text-gray-400 mb-4">{role.description}</p>
            )}

            <div>
              <p className="text-xs font-medium text-gray-300 mb-2.5">Quyền hạn ({role.permissions.length}):</p>
              <div className="flex flex-wrap gap-2">
                {role.permissions.slice(0, 5).map((perm, idx) => (
                  <span
                    key={idx}
                    className="px-2.5 py-1 text-xs bg-[#1E293B] text-gray-400 border border-gray-700 rounded-md"
                  >
                    {perm}
                  </span>
                ))}
                {role.permissions.length > 5 && (
                  <span className="px-2.5 py-1 text-xs bg-gray-800 text-gray-400 border border-gray-700 rounded-md">
                    +{role.permissions.length - 5} more
                  </span>
                )}
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Create/Edit Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-[60] p-4">
          <div className="bg-[#111827] border border-gray-800 rounded-2xl shadow-2xl max-w-2xl w-full max-h-[90vh] overflow-y-auto">
            <div className="p-6 border-b border-gray-800 flex items-center justify-between">
              <h3 className="text-lg font-bold text-white tracking-wide">
                {editingRole ? `Chỉnh sửa vai trò: ${editingRole.display_name}` : 'Tạo vai trò mới'}
              </h3>
              <button onClick={() => setShowModal(false)} className="text-gray-400 hover:text-gray-300 transition-colors">
                <X className="w-5 h-5" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-6 space-y-5">
              {editingRole?.is_system && (
                <div className="bg-amber-500/10 border border-amber-500/20 rounded-xl p-4 text-sm text-amber-200">
                  <strong className="text-amber-300">Lưu ý:</strong> Vai trò hệ thống chỉ có thể chỉnh sửa quyền hạn và trạng thái.
                </div>
              )}

              {!editingRole?.is_system && (
                <>
                  <div>
                    <label className="block text-sm font-medium text-gray-300 mb-2">
                      Mã vai trò <span className="text-rose-500">*</span>
                    </label>
                    <input
                      type="text"
                      value={formData.name}
                      onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                      className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:outline-none text-white placeholder-gray-500"
                      placeholder="e.g., content_moderator"
                      required
                      disabled={!!editingRole}
                    />
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-gray-300 mb-2">
                      Tên hiển thị <span className="text-rose-500">*</span>
                    </label>
                    <input
                      type="text"
                      value={formData.display_name}
                      onChange={(e) => setFormData({ ...formData, display_name: e.target.value })}
                      className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:outline-none text-white placeholder-gray-500"
                      placeholder="e.g., Người kiểm duyệt nội dung"
                      required
                    />
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-gray-300 mb-2">Mô tả</label>
                    <textarea
                      value={formData.description}
                      onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                      className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:outline-none text-white placeholder-gray-500"
                      rows={2}
                      placeholder="Mô tả vai trò này..."
                    />
                  </div>
                </>
              )}

              <div>
                <label className="block text-sm font-medium text-gray-300 mb-2">
                  Quyền hạn <span className="text-rose-500">*</span>
                </label>
                <div className="border border-gray-800 bg-[#1E293B] rounded-xl p-4 max-h-60 overflow-y-auto">
                  <div className="grid grid-cols-2 gap-3">
                    {availablePermissions.map((permission) => (
                      <label key={permission} className="flex items-center space-x-3 cursor-pointer hover:bg-gray-800 p-2 rounded-lg transition-colors">
                        <input
                          type="checkbox"
                          checked={formData.permissions.includes(permission)}
                          onChange={() => togglePermission(permission)}
                          className="w-4 h-4 rounded bg-[#111827] border-gray-600 text-indigo-600 focus:ring-indigo-500 focus:ring-offset-gray-900"
                        />
                        <span className="text-sm font-medium text-gray-300">{permission}</span>
                      </label>
                    ))}
                  </div>
                </div>
                <p className="text-xs text-gray-400 mt-2 font-medium">
                  Đã chọn: <span className="text-indigo-400">{formData.permissions.length}</span> quyền
                </p>
              </div>

              <div className="flex items-center space-x-3 pt-2">
                <input
                  type="checkbox"
                  id="is_active"
                  checked={formData.is_active}
                  onChange={(e) => setFormData({ ...formData, is_active: e.target.checked })}
                  className="w-4 h-4 rounded bg-[#111827] border-gray-600 text-indigo-600 focus:ring-indigo-500 focus:ring-offset-gray-900"
                />
                <label htmlFor="is_active" className="text-sm font-medium text-gray-300">
                  Vai trò đang hoạt động
                </label>
              </div>

              <div className="flex justify-end space-x-3 pt-6 border-t border-gray-800">
                <button
                  type="button"
                  onClick={() => setShowModal(false)}
                  className="px-6 py-2.5 bg-[#1E293B] text-gray-300 border border-gray-700 rounded-xl hover:bg-gray-800 transition-colors font-medium"
                >
                  Hủy
                </button>
                <button
                  type="submit"
                  className="px-6 py-2.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-colors shadow-sm shadow-indigo-500/20 font-medium"
                >
                  {editingRole ? 'Cập nhật' : 'Tạo vai trò'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Info Box */}
      <div className="bg-indigo-500/10 border border-indigo-500/20 rounded-xl p-4">
        <p className="text-sm text-indigo-200">
          <strong className="text-indigo-300">Lưu ý:</strong> Vai trò hệ thống (Super Admin, Admin, Manager, Analyst, Viewer) không thể xóa. 
          Thay đổi quyền hạn sẽ ảnh hưởng đến tất cả người dùng có vai trò đó.
        </p>
      </div>
    </div>
  );
}

frontend/src/app/dashboard/settings/Secu:
'use client';

import { useState } from 'react';
import { Lock, Save } from 'lucide-react';
import toast from 'react-hot-toast';

export default function SecuritySettings() {
  const [saving, setSaving] = useState(false);
  const [passwords, setPasswords] = useState({
    current: '',
    new: '',
    confirm: ''
  });

  const handleChangePassword=***REDACTED*** () => {
    if (saving) return; // Prevent double-click

    // Validation
    if (!passwords.current || !passwords.new || !passwords.confirm) {
      toast.error('❌ Vui lòng điền đầy đủ thông tin');
      return;
    }

    if (passwords.new !== passwords.confirm) {
      toast.error('❌ Mật khẩu mới không khớp');
      return;
    }

    if (passwords.new.length < 8) {
      toast.error('❌ Mật khẩu phải có ít nhất 8 ký tự');
      return;
    }

    setSaving(true);
    try {
      const token=***REDACTED***'access_token');
      const response = await fetch('https://social-listening-backend.onrender.com/api/auth/me/change-password', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          current_password=***REDACTED***,
          new_password=***REDACTED***,
          confirm_password=***REDACTED***
        })
      });

      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.detail || 'Failed to change password');
      }

      toast.success('✅ Đã đổi mật khẩu thành công');
      setPasswords({ current: '', new: '', confirm: '' });
    } catch (error: any) {
      console.error('Error changing password:', error);
      toast.error(`❌ ${error.message || 'Lỗi khi đổi mật khẩu'}`);
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <h2 className="text-xl font-bold text-white tracking-wide">Bảo mật tài khoản</h2>
        <p className="text-sm text-gray-400 mt-1">Quản lý mật khẩu và bảo mật</p>
      </div>

      {/* Change Password */}
      <div className="bg-[#111827] border border-gray-800 rounded-xl shadow-sm p-6 space-y-6">
        <h3 className="text-lg font-bold text-white flex items-center">
          <Lock className="w-5 h-5 mr-2 text-indigo-400" />
          Đổi mật khẩu
        </h3>

        <div className="space-y-4 max-w-2xl">
          <div>
            <label className="block text-sm font-medium text-gray-300 mb-2">
              Mật khẩu hiện tại *
            </label>
            <input
              type="password"
              value={passwords.current}
              onChange={(e) => setPasswords({ ...passwords, current: e.target.value })}
              className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white placeholder-gray-500"
              placeholder="••••••••"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-300 mb-2">
              Mật khẩu mới *
            </label>
            <input
              type="password"
              value={passwords.new}
              onChange={(e) => setPasswords({ ...passwords, new: e.target.value })}
              className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white placeholder-gray-500"
              placeholder="••••••••"
            />
            <p className="text-xs text-gray-500 mt-1.5 font-medium">Tối thiểu 8 ký tự</p>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-300 mb-2">
              Xác nhận mật khẩu mới *
            </label>
            <input
              type="password"
              value={passwords.confirm}
              onChange={(e) => setPasswords({ ...passwords, confirm: e.target.value })}
              className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white placeholder-gray-500"
              placeholder="••••••••"
            />
          </div>
        </div>

        <div className="flex justify-end pt-4 border-t border-gray-800">
          <button
            onClick={handleChangePassword}
            disabled={saving}
            className="flex items-center px-6 py-2.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-colors disabled:bg-gray-800 disabled:text-gray-500 disabled:cursor-not-allowed shadow-sm shadow-indigo-500/20 font-medium"
          >
            <Save className="w-4 h-4 mr-2" />
            {saving ? 'Đang lưu...' : 'Đổi mật khẩu'}
          </button>
        </div>
      </div>

      {/* Security Info */}
      <div className="bg-indigo-500/10 border border-indigo-500/20 rounded-xl p-4">
        <p className="text-sm text-indigo-200">
          <strong className="text-indigo-300">Lưu ý:</strong> Sau khi đổi mật khẩu, bạn sẽ cần đăng nhập lại trên tất cả thiết bị.
        </p>
      </div>
    </div>
  );
}

frontend/src/app/dashboard/settings/Sess:
'use client';

import { useState, useEffect } from 'react';
import { Clock, Monitor, LogOut, AlertCircle, Trash2 } from 'lucide-react';
import toast from 'react-hot-toast';

interface Session {
  id: number;
  device_type: string;
  ip_address: string | null;
  user_agent: string | null;
  location: string | null;
  created_at: string;
  last_active_at: string;
  expires_at: string;
}

export default function SessionsSettings() {
  const [sessions, setSessions] = useState<Session[]>([]);
  const [loading, setLoading] = useState(true);
  const [revoking, setRevoking] = useState<number | null>(null);

  useEffect(() => {
    loadSessions();
  }, []);

  const loadSessions = async () => {
    try {
      const token=***REDACTED***'access_token');
      const response = await fetch('https://social-listening-backend.onrender.com/api/auth/me/sessions', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });

      if (response.ok) {
        const data = await response.json();
        setSessions(data.sessions || []);
      } else {
        toast.error('Không thể tải danh sách phiên đăng nhập');
      }
    } catch (error) {
      console.error('Failed to load sessions:', error);
      toast.error('Không thể tải danh sách phiên đăng nhập');
    } finally {
      setLoading(false);
    }
  };

  const revokeSession = async (sessionId: number) => {
    if (revoking) return;

    if (!confirm('Bạn có chắc muốn đăng xuất phiên này?')) {
      return;
    }

    setRevoking(sessionId);
    try {
      const token=***REDACTED***'access_token');
      const response = await fetch(`https://social-listening-backend.onrender.com/api/auth/me/sessions/${sessionId}/revoke`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });

      if (response.ok) {
        toast.success('✅ Đã đăng xuất phiên thành công');
        loadSessions(); // Reload sessions
      } else {
        toast.error('Không thể đăng xuất phiên');
      }
    } catch (error) {
      console.error('Failed to revoke session:', error);
      toast.error('Không thể đăng xuất phiên');
    } finally {
      setRevoking(null);
    }
  };

  const logoutAllOtherSessions = async () => {
    if (!confirm('Bạn có chắc muốn đăng xuất tất cả các phiên khác?')) {
      return;
    }

    try {
      const token=***REDACTED***'access_token');
      const response = await fetch('https://social-listening-backend.onrender.com/api/auth/me/logout-other-sessions', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });

      if (response.ok) {
        toast.success('✅ Đã đăng xuất tất cả các phiên khác');
        loadSessions(); // Reload sessions
      } else {
        toast.error('Không thể đăng xuất các phiên khác');
      }
    } catch (error) {
      console.error('Failed to logout other sessions:', error);
      toast.error('Không thể đăng xuất các phiên khác');
    }
  };

  const formatDate = (dateString: string) => {
    try {
      return new Date(dateString).toLocaleString('vi-VN');
    } catch {
      return 'N/A';
    }
  };

  const getDeviceIcon = (deviceType: string) => {
    switch (deviceType) {
      case 'mobile':
        return '📱';
      case 'tablet':
        return '📱';
      case 'desktop':
        return '💻';
      default:
        return '🖥️';
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <h2 className="text-xl font-semibold text-gray-900">Phiên đăng nhập</h2>
        <p className="text-sm text-gray-600 mt-1">Quản lý các phiên đăng nhập của bạn</p>
      </div>

      {/* Sessions List */}
      {sessions.length === 0 ? (
        <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-6">
          <div className="flex items-start">
            <AlertCircle className="w-6 h-6 text-yellow-600 mr-3 flex-shrink-0 mt-0.5" />
            <div>
              <h3 className="text-sm font-semibold text-yellow-900 mb-2">
                Không có phiên đăng nhập nào
              </h3>
              <p className="text-sm text-yellow-800">
                Bạn chưa có phiên đăng nhập nào được lưu trữ. Đăng nhập lại để tạo phiên mới.
              </p>
            </div>
          </div>
        </div>
      ) : (
        <>
          {/* Logout All Button */}
          <div className="flex justify-end">
            <button
              onClick={logoutAllOtherSessions}
              className="flex items-center px-4 py-2 text-red-600 border border-red-300 rounded-lg hover:bg-red-50 transition-colors"
            >
              <LogOut className="w-4 h-4 mr-2" />
              Đăng xuất tất cả phiên khác
            </button>
          </div>

          {/* Sessions */}
          <div className="space-y-4">
            {sessions.map((session) => (
              <div key={session.id} className="bg-white border border-gray-200 rounded-lg p-6">
                <div className="flex items-start justify-between">
                  <div className="flex items-start space-x-4 flex-1">
                    <div className="text-3xl">
                      {getDeviceIcon(session.device_type)}
                    </div>
                    <div className="flex-1">
                      <p className="text-sm font-medium text-gray-900">
                        {session.device_type === 'unknown' ? 'Thiết bị không xác định' : session.device_type}
                      </p>
                      {session.user_agent && (
                        <p className="text-xs text-gray-500 mt-1 line-clamp-1">
                          {session.user_agent}
                        </p>
                      )}
                      {session.ip_address && (
                        <p className="text-xs text-gray-500 mt-1">
                          IP: {session.ip_address}
                        </p>
                      )}
                      {session.location && (
                        <p className="text-xs text-gray-500 mt-1">
                          📍 {session.location}
                        </p>
                      )}
                      <div className="flex items-center mt-2 text-xs text-gray-500 space-x-4">
                        <div className="flex items-center">
                          <Clock className="w-3 h-3 mr-1" />
                          Đăng nhập: {formatDate(session.created_at)}
                        </div>
                        <div className="flex items-center">
                          <Clock className="w-3 h-3 mr-1" />
                          Hoạt động: {formatDate(session.last_active_at)}
                        </div>
                      </div>
                    </div>
                  </div>
                  <button
                    onClick={() => revokeSession(session.id)}
                    disabled={revoking === session.id}
                    className="flex items-center px-3 py-2 text-red-600 border border-red-300 rounded-lg hover:bg-red-50 transition-colors disabled:opacity-50 disabled:cursor-not-allowed ml-4"
                  >
                    <Trash2 className="w-4 h-4 mr-2" />
                    {revoking === session.id ? 'Đang xóa...' : 'Đăng xuất'}
                  </button>
                </div>
              </div>
            ))}
          </div>
        </>
      )}

      {/* Info */}
      <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
        <p className="text-sm text-blue-800">
          <strong>Lưu ý:</strong> Khi bạn đăng xuất một phiên, token của phiên đó sẽ bị vô hiệu hóa ngay lập tức.
          Nếu phát hiện hoạt động đáng ngờ, hãy đăng xuất tất cả các phiên và đổi mật khẩu.
        </p>
      </div>
    </div>
  );
}

