          onChange={(e) => setFilterActive(e.target.value === '' ? null : e.target.value === 'true')}
          className="px-4 py-2.5 bg-[#1E293B] border border-gray-700 text-gray-300 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:outline-none transition-shadow"
        >
          <option value="">Tất cả trạng thái</option>
          <option value="true">Đang hoạt động</option>
          <option value="false">Vô hiệu hóa</option>
        </select>

        <select
          value={filterSuperuser === null ? '' : String(filterSuperuser)}
          onChange={(e) => setFilterSuperuser(e.target.value === '' ? null : e.target.value === 'true')}
          className="px-4 py-2.5 bg-[#1E293B] border border-gray-700 text-gray-300 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:outline-none transition-shadow"
        >
          <option value="">Tất cả quyền</option>
          <option value="true">Quản trị viên</option>
          <option value="false">Người dùng</option>
        </select>

        {/* Create button */}
        <button
          onClick={() => setShowCreateModal(true)}
          className="flex items-center px-6 py-2.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-colors shadow-sm shadow-indigo-500/20 font-medium whitespace-nowrap"
        >
          <Plus className="w-5 h-5 mr-2" />
          Thêm người dùng
        </button>
      </div>

      {/* Users table */}
      <div className="bg-[#111827] rounded-xl border border-gray-800 overflow-hidden shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-[#1E293B] border-b border-gray-800">
              <tr>
                <th className="px-6 py-4 text-left text-xs font-medium text-gray-400 uppercase tracking-wider">
                  Người dùng
                </th>
                <th className="px-6 py-4 text-left text-xs font-medium text-gray-400 uppercase tracking-wider">
                  Quyền
                </th>
                <th className="px-6 py-4 text-left text-xs font-medium text-gray-400 uppercase tracking-wider">
                  Trạng thái
                </th>
                <th className="px-6 py-4 text-left text-xs font-medium text-gray-400 uppercase tracking-wider">
                  Ngày tạo
                </th>
                <th className="px-6 py-4 text-right text-xs font-medium text-gray-400 uppercase tracking-wider">
                  Hành động
                </th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-800">
              {users.map((user) => (
                <tr key={user.id} className="hover:bg-[#1E293B]/50 transition-colors">
                  <td className="px-6 py-4">
                    <div>
                      <div className="font-medium text-gray-200">{user.full_name || 'N/A'}</div>
                      <div className="text-sm text-gray-400">{user.email}</div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    {user.is_superuser ? (
                      <span className="inline-flex items-center px-2.5 py-1 rounded-md text-xs font-medium bg-purple-500/10 text-purple-400 border border-purple-500/20">
                        <Crown className="w-3.5 h-3.5 mr-1" />
                        Quản trị viên
                      </span>
                    ) : (
                      <span className="inline-flex items-center px-2.5 py-1 rounded-md text-xs font-medium bg-[#1E293B] text-gray-400 border border-gray-700">
                        <UserIcon className="w-3.5 h-3.5 mr-1" />
                        Người dùng
                      </span>
                    )}
                  </td>
                  <td className="px-6 py-4">
                    {user.is_active ? (
                      <span className="inline-flex items-center px-2.5 py-1 rounded-md text-xs font-medium bg-emerald-500/10 text-emerald-400 border border-emerald-500/20">
                        ✓ Hoạt động
                      </span>
                    ) : (
                      <span className="inline-flex items-center px-2.5 py-1 rounded-md text-xs font-medium bg-rose-500/10 text-rose-400 border border-rose-500/20">
                        ✗ Vô hiệu hóa
                      </span>
                    )}
                  </td>
                  <td className="px-6 py-4 text-sm text-gray-400">
                    {new Date(user.created_at).toLocaleDateString('vi-VN')}
                  </td>
                  <td className="px-6 py-4 text-right space-x-2">
                    <button
                      onClick={() => {
                        setSelectedUser(user);
                        setShowEditModal(true);
                      }}
                      className="inline-flex items-center p-2 text-indigo-400 hover:bg-indigo-500/10 rounded-lg transition-colors"
                      title="Sửa"
                    >
                      <Edit className="w-4 h-4" />
                    </button>
                    <button
                      onClick={() => {
                        setSelectedUser(user);
                        setShowResetPasswordModal(true);
                      }}
                      className="inline-flex items-center p-2 text-amber-400 hover:bg-amber-500/10 rounded-lg transition-colors"
                      title="Đặt lại mật khẩu"
                    >
                      <Key className="w-4 h-4" />
                    </button>
                    <button
                      onClick={() => setConfirmToggle({ show: true, user })}
                      className="inline-flex items-center p-2 text-gray-400 hover:bg-gray-800 rounded-lg transition-colors"
                      title={user.is_active ? 'Vô hiệu hóa' : 'Kích hoạt'}
                    >
                      <Power className="w-4 h-4" />
                    </button>
                    <button
                      onClick={() => setConfirmDelete({ show: true, user })}
                      className="inline-flex items-center p-2 text-rose-400 hover:bg-rose-500/10 rounded-lg transition-colors"
                      title="Xóa"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {users.length === 0 && (
          <div className="text-center py-12 text-gray-400">
            Không tìm thấy người dùng nào
          </div>
        )}
      </div>

      {/* Modals */}
      {showCreateModal && (
        <UserFormModal
          title="Thêm người dùng mới"
          onClose={() => setShowCreateModal(false)}
          onSubmit={handleCreateUser}
        />
      )}

      {showEditModal && selectedUser && (
        <UserFormModal
          title="Sửa thông tin người dùng"
          user={selectedUser}
          onClose={() => {
            setShowEditModal(false);
            setSelectedUser(null);
          }}
          onSubmit={(data) => handleUpdateUser(selectedUser.id, data)}
        />
      )}

      {showResetPasswordModal && selectedUser && (
        <ResetPasswordModal
          user={selectedUser}
          onClose={() => {
            setShowResetPasswordModal(false);
            setSelectedUser(null);
          }}
          onSubmit={(password) => handleResetPassword(selectedUser.id, password)}
        />
      )}

      {/* Confirm dialogs */}
      <ConfirmDialog
        isOpen={confirmDelete.show}
        title="Xác nhận xóa người dùng"
        message={`Bạn có chắc chắn muốn xóa người dùng "${confirmDelete.user?.email}"? Hành động này không thể hoàn tác.`}
        type="danger"
        onConfirm={() => {
          if (confirmDelete.user) {
            handleDeleteUser(confirmDelete.user.id);
          }
          setConfirmDelete({ show: false, user: null });
        }}
        onClose={() => setConfirmDelete({ show: false, user: null })}
      />

      <ConfirmDialog
        isOpen={confirmToggle.show}
        title={confirmToggle.user?.is_active ? 'Vô hiệu hóa người dùng' : 'Kích hoạt người dùng'}
        message={`Bạn có chắc chắn muốn ${confirmToggle.user?.is_active ? 'vô hiệu hóa' : 'kích hoạt'} người dùng "${confirmToggle.user?.email}"?`}
        type="warning"
        onConfirm={() => {
          if (confirmToggle.user) {
            handleToggleActive(confirmToggle.user.id);
          }
          setConfirmToggle({ show: false, user: null });
        }}
        onClose={() => setConfirmToggle({ show: false, user: null })}
      />
    </div>
  );
}

function StatCard({ label, value, color }: { label: string; value: number; color: string }) {
  const colorClasses = {
    blue: 'bg-blue-500/10 text-blue-400 border border-blue-500/20',
    green: 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20',
    gray: 'bg-[#1E293B] text-gray-400 border border-gray-700',
    purple: 'bg-purple-500/10 text-purple-400 border border-purple-500/20',
    indigo: 'bg-indigo-500/10 text-indigo-400 border border-indigo-500/20',
  };

  return (
    <div className={`p-5 rounded-xl shadow-sm ${colorClasses[color as keyof typeof colorClasses]}`}>
      <div className="text-3xl font-bold tracking-tight">{value}</div>
      <div className="text-sm mt-1 opacity-80 font-medium">{label}</div>
    </div>
  );
}

function UserFormModal({
  title,
  user,
  onClose,
  onSubmit,
}: {
  title: string;
  user?: User;
  onClose: () => void;
  onSubmit: (data: any) => void;
}) {
  const [formData, setFormData] = useState({
    email: user?.email || '',
    password: '',
    full_name: user?.full_name || '',
    is_superuser: user?.is_superuser || false,
    is_active: user?.is_active ?? true,
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    
    // For edit, only send changed fields
    if (user) {
      const updates: any = {};
      if (formData.email !== user.email) updates.email = formData.email;
      if (formData.full_name !== user.full_name) updates.full_name = formData.full_name;
      if (formData.is_superuser !== user.is_superuser) updates.is_superuser = formData.is_superuser;
      if (formData.is_active !== user.is_active) updates.is_active = formData.is_active;
      onSubmit(updates);
    } else {
      // For create, send all fields
      onSubmit(formData);
    }
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/60 backdrop-blur-sm">
      <div className="bg-[#111827] border border-gray-800 rounded-2xl shadow-2xl w-full max-w-md mx-4">
        <div className="flex items-center justify-between p-6 border-b border-gray-800">
          <h3 className="text-lg font-bold text-white tracking-wide">{title}</h3>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-300 transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-300 mb-2">
              Email *
            </label>
            <input
              type="email"
              required
              value={formData.email}
              onChange={(e) => setFormData({ ...formData, email: e.target.value })}
              className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:outline-none text-white placeholder-gray-500"
            />
          </div>

          {!user && (
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">
                Mật khẩu *
              </label>
              <input
                type="password"
                required
                value={formData.password}
                onChange={(e) => setFormData({ ...formData, password=***REDACTED*** })}
                className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:outline-none text-white placeholder-gray-500"
              />
            </div>
          )}

          <div>
            <label className="block text-sm font-medium text-gray-300 mb-2">
              Họ tên
            </label>
            <input
              type="text"
              value={formData.full_name}
              onChange={(e) => setFormData({ ...formData, full_name: e.target.value })}
              className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:outline-none text-white placeholder-gray-500"
            />
          </div>

          <div className="flex items-center space-x-3 pt-2">
            <input
              type="checkbox"
              id="is_superuser"
              checked={formData.is_superuser}
              onChange={(e) => setFormData({ ...formData, is_superuser: e.target.checked })}
              className="w-4 h-4 text-indigo-600 bg-[#1E293B] border-gray-700 rounded focus:ring-indigo-500 focus:ring-offset-gray-900"
            />
            <label htmlFor="is_superuser" className="text-sm font-medium text-gray-300">
              Quản trị viên (Superuser)
            </label>
          </div>

          <div className="flex items-center space-x-3">
            <input
              type="checkbox"
              id="is_active"
              checked={formData.is_active}
              onChange={(e) => setFormData({ ...formData, is_active: e.target.checked })}
              className="w-4 h-4 text-indigo-600 bg-[#1E293B] border-gray-700 rounded focus:ring-indigo-500 focus:ring-offset-gray-900"
            />
            <label htmlFor="is_active" className="text-sm font-medium text-gray-300">
              Kích hoạt tài khoản
            </label>
          </div>

          <div className="flex gap-3 pt-6 border-t border-gray-800">
            <button
              type="button"
              onClick={onClose}
              className="flex-1 px-4 py-2.5 border border-gray-700 bg-[#1E293B] text-gray-300 rounded-xl hover:bg-gray-800 transition-colors font-medium"
            >
              Hủy
            </button>
            <button
              type="submit"
              className="flex-1 px-4 py-2.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-colors font-medium shadow-sm shadow-indigo-500/20"
            >
              {user ? 'Cập nhật' : 'Tạo mới'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

function ResetPasswordModal({
  user,
  onClose,
  onSubmit,
}: {
  user: User;
  onClose: () => void;
  onSubmit: (password=***REDACTED*** => void;
}) {
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (password !== confirmPassword) {
      alert('Mật khẩu xác nhận không khớp');
      return;
    }
    if (password.length < 6) {
      alert('Mật khẩu phải có ít nhất 6 ký tự');
      return;
    }
    onSubmit(password);
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/60 backdrop-blur-sm">
      <div className="bg-[#111827] border border-gray-800 rounded-2xl shadow-2xl w-full max-w-md mx-4">
        <div className="flex items-center justify-between p-6 border-b border-gray-800">
          <h3 className="text-lg font-bold text-white tracking-wide">Đặt lại mật khẩu</h3>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-300 transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div className="text-sm text-gray-400 mb-6 bg-[#1E293B] p-4 rounded-xl border border-gray-700">
            Đặt lại mật khẩu cho: <strong className="text-white block mt-1">{user.email}</strong>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-300 mb-2">
              Mật khẩu mới *
            </label>
            <input
              type="password"
              required
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:outline-none text-white placeholder-gray-500"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-300 mb-2">
              Xác nhận mật khẩu *
            </label>
            <input
              type="password"
              required
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:outline-none text-white placeholder-gray-500"
            />
          </div>

          <div className="flex gap-3 pt-6 border-t border-gray-800">
            <button
              type="button"
              onClick={onClose}
              className="flex-1 px-4 py-2.5 border border-gray-700 bg-[#1E293B] text-gray-300 rounded-xl hover:bg-gray-800 transition-colors font-medium"
            >
              Hủy
            </button>
            <button
              type="submit"
              className="flex-1 px-4 py-2.5 bg-amber-500/20 text-amber-500 border border-amber-500/30 rounded-xl hover:bg-amber-500/30 transition-colors font-medium shadow-sm shadow-amber-500/10"
            >
              Đặt lại mật khẩu
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { Plus, Trash2, Search, Globe, Facebook, Youtube, Clock } from 'lucide-react';
import { sources as sourcesApi, getErrorMessage, getUserFacingErrorMessage } from '@/lib/api';
import toast, { Toaster } from 'react-hot-toast';
import ConfirmDialog from '@/components/ConfirmDialog';
import ScheduleSelector from '@/components/ScheduleSelector';

interface Source {
  id: number;
  name: string;
  url: string;
  source_type: string;
  is_active: boolean;
  crawl_frequency: string;
  crawl_time: string | null;
  crawl_day_of_week: number | null;
  crawl_day_of_month: number | null;
  crawl_month: number | null;
  next_crawl_at: string | null;
  last_crawled_at: string | null;
  created_at: string;
}

export default function SourcesPage() {
  const [sources, setSources] = useState<Source[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [deleteConfirm, setDeleteConfirm] = useState<{ isOpen: boolean; sourceId: number | null; sourceName: string }>({
    isOpen: false,
    sourceId: null,
    sourceName: ''
  });
  const [showTestSources, setShowTestSources] = useState(false);
  const [newSource, setNewSource] = useState({
    name: '',
    url: '',
    source_type: 'website',
    crawl_frequency: 'manual' as 'manual' | 'daily' | 'weekly' | 'monthly' | 'yearly',
    schedule: {
      hours: [] as number[],
      daysOfWeek: [] as number[],
      daysOfMonth: [] as number[],
      months: [] as number[],
      time: '09:00'
    }
  });

  useEffect(() => {
    fetchSources();
  }, []);

  const fetchSources = async () => {
    try {
      setLoading(true);
      const data = await sourcesApi.list();
      setSources(data);
    } catch (error: any) {
      console.error('Error fetching sources:', error);
      // Don't toast for 401 — global interceptor handles redirect
      if (error?.response?.status !== 401) {
        toast.error(getUserFacingErrorMessage(
          error,
          'Lỗi khi tải danh sách nguồn. Vui lòng kiểm tra backend hoặc database migration.'
        ));
      }
    } finally {
      setLoading(false);
    }
  };

  const handleAddSource = async () => {
    if (!newSource.name.trim() || !newSource.url.trim()) {
      toast.error('Vui lòng nhập đầy đủ thông tin');
      return;
    }

    try {
      const payload: any = {
        name: newSource.name,
        url: newSource.url,
        source_type: newSource.source_type,
        is_active: true,
        crawl_frequency: newSource.crawl_frequency
      };

      // Add schedule fields based on frequency
      if (newSource.crawl_frequency === 'daily') {
        payload.schedule_hours = newSource.schedule.hours;
        if (newSource.schedule.hours.length === 0) {
          toast.error('Vui lòng chọn ít nhất 1 giờ quét');
          return;
        }
      } else if (newSource.crawl_frequency === 'weekly') {
        payload.schedule_days_of_week = newSource.schedule.daysOfWeek;
        payload.crawl_time = newSource.schedule.time;
        if (newSource.schedule.daysOfWeek.length === 0) {
          toast.error('Vui lòng chọn ít nhất 1 ngày trong tuần');
          return;
        }
      } else if (newSource.crawl_frequency === 'monthly') {
        payload.schedule_days_of_month = newSource.schedule.daysOfMonth;
        payload.crawl_time = newSource.schedule.time;
        if (newSource.schedule.daysOfMonth.length === 0) {
          toast.error('Vui lòng chọn ít nhất 1 ngày trong tháng');
          return;
        }
      } else if (newSource.crawl_frequency === 'yearly') {
        payload.schedule_months = newSource.schedule.months;
        payload.schedule_days_of_month = newSource.schedule.daysOfMonth;
        payload.crawl_time = newSource.schedule.time;
        if (newSource.schedule.months.length === 0 || newSource.schedule.daysOfMonth.length === 0) {
          toast.error('Vui lòng chọn ít nhất 1 tháng và 1 ngày');
          return;
        }
      }

      await sourcesApi.create(payload);
      
      setShowAddModal(false);
      setNewSource({ 
        name: '', 
        url: '', 
        source_type: 'website',
        crawl_frequency: 'manual',
        schedule: {
          hours: [],
          daysOfWeek: [],
          daysOfMonth: [],
          months: [],
          time: '09:00'
        }
      });
      toast.success('Thêm nguồn thành công!');
      fetchSources();
    } catch (error: any) {
      console.error('Error adding source:', error);
      toast.error(`Lỗi khi thêm nguồn: ${getErrorMessage(error)}`);
    }
  };

  const handleDeleteSource = async () => {
    if (!deleteConfirm.sourceId) return;

    try {
      await sourcesApi.delete(deleteConfirm.sourceId);
      toast.success('Xóa nguồn thành công!');
      fetchSources();
    } catch (error: any) {
      console.error('Error deleting source:', error);
      toast.error(`Lỗi khi xóa nguồn: ${getErrorMessage(error)}`);
    }
  };

  const handleToggleActive = async (source: Source) => {
    try {
      await sourcesApi.update(source.id, {
        is_active: !source.is_active
      });
      fetchSources();
      toast.success(`Đã ${!source.is_active ? 'bật' : 'tắt'} nguồn`);
    } catch (error: any) {
      console.error('Error toggling source:', error);
      toast.error(`Lỗi khi cập nhật nguồn: ${getErrorMessage(error)}`);
    }
  };

  const filteredSources = sources.filter(s => {
    const matchesSearch = s.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          s.url.toLowerCase().includes(searchTerm.toLowerCase());
    const isTest = s.url.includes('example.com') || /daily source|weekly source|monthly source|yearly source/i.test(s.name);
    
    if (!showTestSources && isTest) return false;
    return matchesSearch;
  });

  const getSourceIcon = (type: string) => {
    if (type.includes('facebook')) return <Facebook className="w-5 h-5 text-blue-600" />;
    if (type.includes('youtube')) return <Youtube className="w-5 h-5 text-red-600" />;
    return <Globe className="w-5 h-5 text-gray-600" />;
  };

  const getSourceTypeText = (type: string) => {
    const typeMap: Record<string, string> = {
      'facebook_page': 'Facebook Page',
      'facebook_group': 'Facebook Group',
      'facebook_profile': 'Facebook Profile',
      'youtube_channel': 'YouTube Channel',
      'youtube_video': 'YouTube Video',
      'website': 'Website',
      'news': 'News',
      'rss': 'RSS Feed',
      'forum': 'Forum',
      'manual_url': 'Manual URL'
    };
    return typeMap[type] || type;
  };

  const getFrequencyText = (frequency: string) => {
    switch (frequency) {
      case 'daily': return 'Hằng ngày';
      case 'weekly': return 'Hằng tuần';
      case 'monthly': return 'Hằng tháng';
      case 'yearly': return 'Hằng năm';
      default: return 'Thủ công';
    }
  };

  const getScheduleDescription = (source: Source) => {
    if (source.crawl_frequency === 'manual') return 'Quét thủ công';
    
    const time = source.crawl_time || '09:00';
    
    if (source.crawl_frequency === 'daily') {
      return `Hằng ngày lúc ${time}`;
    } else if (source.crawl_frequency === 'weekly') {
      const days = ['Thứ 2', 'Thứ 3', 'Thứ 4', 'Thứ 5', 'Thứ 6', 'Thứ 7', 'Chủ nhật'];
      const dayName = days[source.crawl_day_of_week || 0];
      return `Hằng tuần vào ${dayName} lúc ${time}`;
    } else if (source.crawl_frequency === 'monthly') {
      return `Hằng tháng ngày ${source.crawl_day_of_month || 1} lúc ${time}`;
    } else if (source.crawl_frequency === 'yearly') {
      const months = ['', 'Tháng 1', 'Tháng 2', 'Tháng 3', 'Tháng 4', 'Tháng 5', 'Tháng 6',
                     'Tháng 7', 'Tháng 8', 'Tháng 9', 'Tháng 10', 'Tháng 11', 'Tháng 12'];
      const monthName = months[source.crawl_month || 1];
      return `Hằng năm ${monthName} ngày ${source.crawl_day_of_month || 1} lúc ${time}`;
    }
    
    return 'Không xác định';
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="text-lg text-gray-400 font-medium tracking-wide">Đang tải...</div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <Toaster position="top-right" />
      
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-6">
        <div>
          <h1 className="text-2xl font-bold text-white tracking-wide">Quản lý nguồn</h1>
          <p className="text-sm text-gray-400 mt-1">
            Quản lý các nguồn dữ liệu để thu thập thông tin
          </p>
        </div>
        <button
          onClick={() => setShowAddModal(true)}
          className="flex items-center px-4 py-2.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition-all duration-200 shadow-sm shadow-indigo-500/20 font-medium"
        >
          <Plus className="w-5 h-5 mr-2" />
          Thêm nguồn
        </button>
      </div>

      {/* Search */}
      <div className="flex flex-col sm:flex-row items-center gap-4 mb-6">
        <div className="relative flex-1 w-full">
          <Search className="absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-500 w-5 h-5" />
          <input
            type="text"
            placeholder="Tìm kiếm nguồn..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-11 pr-4 py-3 bg-[#111827] border border-gray-800 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white placeholder-gray-500 shadow-sm transition-shadow"
          />
        </div>
        <div className="flex items-center gap-3 bg-[#111827] px-4 py-3 border border-gray-800 rounded-xl w-full sm:w-auto">
          <input
            type="checkbox"
            id="showTestSources"
            checked={showTestSources}
            onChange={(e) => setShowTestSources(e.target.checked)}
            className="w-4 h-4 text-indigo-600 bg-gray-800 border-gray-600 rounded focus:ring-indigo-500 focus:ring-offset-gray-900"
          />
          <label htmlFor="showTestSources" className="text-sm font-medium text-gray-300 cursor-pointer select-none">
            Hiện nguồn test
          </label>
        </div>
      </div>

      {/* Sources Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
        {filteredSources.length === 0 ? (
          <div className="col-span-full bg-[#111827] border border-gray-800 rounded-xl shadow-sm p-10 text-center text-gray-400 font-medium tracking-wide">
            <div className="w-16 h-16 rounded-xl bg-[#1E293B] flex items-center justify-center mx-auto mb-4 border border-gray-800 shadow-sm">
              <Globe className="w-8 h-8 text-gray-500" />
            </div>
            {searchTerm ? 'Không tìm thấy nguồn phù hợp.' : 'Không có nguồn nào. Hãy thêm nguồn đầu tiên!'}
          </div>
        ) : (
          filteredSources.map((source) => {
            const isTest = source.url.includes('example.com') || /daily source|weekly source|monthly source|yearly source/i.test(source.name);
            const isSupported = ['rss', 'website'].includes((source.source_type || '').toLowerCase());
            const isUnsupported = !isSupported && source.source_type;

            return (
              <div key={source.id} className="bg-[#111827] rounded-xl shadow-sm border border-gray-800 p-6 transition-all duration-300 hover:border-indigo-500/30 hover:shadow-indigo-500/5 group flex flex-col h-full">
                <div className="flex items-start justify-between mb-5">
                  <div className="flex items-center space-x-3">
                    <div className="p-2.5 bg-[#1E293B] rounded-lg border border-gray-700 group-hover:scale-110 transition-transform duration-300">
                      {getSourceIcon(source.source_type)}
                    </div>
                    <div>
                      <div className="flex items-center gap-2 flex-wrap mb-1">
                        <h3 className="font-semibold text-white tracking-wide truncate max-w-[150px]" title={source.name}>{source.name}</h3>
                        {isTest && (
                          <span className="inline-flex items-center px-1.5 py-0.5 rounded text-[10px] font-bold tracking-wider uppercase bg-orange-500/10 text-orange-400 border border-orange-500/20">
                            Test
                          </span>
                        )}
                        {isUnsupported && (
                          <span className="inline-flex items-center px-1.5 py-0.5 rounded text-[10px] font-bold tracking-wider uppercase bg-rose-500/10 text-rose-400 border border-rose-500/20">
                            Chưa hỗ trợ
                          </span>
                        )}
                      </div>
                      <p className="text-[11px] font-medium tracking-wider uppercase text-gray-500">{getSourceTypeText(source.source_type)}</p>
                    </div>
                  </div>
                <button
                  onClick={() => handleToggleActive(source)}
                  className={`px-2.5 py-1 text-[10px] font-bold tracking-wider uppercase rounded-md transition-colors border ${
                    source.is_active
                      ? 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20 hover:bg-emerald-500/20'
                      : 'bg-gray-800 text-gray-500 border-gray-700 hover:bg-gray-700'
                  }`}
                >
                  {source.is_active ? 'ON' : 'OFF'}
                </button>
              </div>

              <div className="space-y-3 mb-6 flex-1">
                <p className="text-sm text-gray-400 truncate bg-[#0B1220] p-2.5 rounded-lg border border-gray-800" title={source.url}>
                  <span className="font-medium text-gray-500 mr-2 block text-xs uppercase tracking-wider mb-1">URL</span> {source.url}
                </p>
                
                {/* Schedule Info */}
                <div className="flex items-center space-x-3 text-sm text-gray-400 px-1">
                  <Clock className="w-4 h-4 text-indigo-400 flex-shrink-0" />
                  <div className="flex-1 truncate" title={getScheduleDescription(source)}>
                    {getScheduleDescription(source)}
                  </div>
                </div>
                
                {source.next_crawl_at && (
                  <p className="text-xs text-gray-500 px-1 truncate">
                    <span className="font-medium mr-1 text-gray-400">Tiếp theo:</span>
                    {new Date(source.next_crawl_at).toLocaleString('vi-VN')}
                  </p>
                )}
                
                <p className="text-xs text-gray-500 px-1 truncate">
                  <span className="font-medium mr-1 text-gray-400">Gần nhất:</span>
                  {source.last_crawled_at 
                    ? new Date(source.last_crawled_at).toLocaleString('vi-VN')
                    : 'Chưa crawl'
                  }
                </p>
                {(source as any).last_error && (
                  <div className="text-xs text-rose-400 mt-3 p-2.5 bg-rose-500/5 border border-rose-500/20 rounded-lg" title={(source as any).last_error}>
                    <span className="font-semibold text-rose-500 block mb-1 uppercase tracking-wider text-[10px]">Lỗi gần nhất</span>
                    <span className="opacity-90">{(source as any).last_error.substring(0, 100)}{(source as any).last_error.length > 100 ? '...' : ''}</span>
                  </div>
                )}
              </div>

              <div className="flex justify-end pt-4 border-t border-gray-800/50 mt-auto">
                <button
                  onClick={() => setDeleteConfirm({ isOpen: true, sourceId: source.id, sourceName: source.name })}
                  className="p-1.5 text-gray-500 hover:text-rose-400 hover:bg-rose-500/10 rounded-lg transition-colors border border-transparent hover:border-rose-500/20"
                  title="Xóa nguồn"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
              </div>
            </div>
          );
        })
        )}
      </div>

      {/* Delete Confirm Dialog */}
      <ConfirmDialog
        isOpen={deleteConfirm.isOpen}
        onClose={() => setDeleteConfirm({ isOpen: false, sourceId: null, sourceName: '' })}
        onConfirm={handleDeleteSource}
        title="Xóa nguồn"
        message={`Bạn có chắc muốn xóa nguồn "${deleteConfirm.sourceName}"?`}
        confirmText="Xóa"
        cancelText="Hủy"
        type="danger"
      />

      {/* Add Modal */}
      {showAddModal && (
        <div className="fixed inset-0 bg-black/70 backdrop-blur-sm flex items-center justify-center z-50 p-4">
          <div className="bg-[#111827] border border-gray-800 rounded-2xl shadow-2xl w-full max-w-lg max-h-[90vh] overflow-y-auto custom-scrollbar">
            <div className="p-6 border-b border-gray-800 bg-[#0B1220]/50 sticky top-0 z-10">
              <h2 className="text-xl font-bold text-white">Thêm nguồn mới</h2>
            </div>
            
            <div className="p-6 space-y-5">
              <div>
                <label className="block text-sm font-medium text-gray-300 mb-2">
                  Tên nguồn *
                </label>
                <input
                  type="text"
                  value={newSource.name}
                  onChange={(e) => setNewSource({ ...newSource, name: e.target.value })}
                  className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white placeholder-gray-500"
                  placeholder="Ví dụ: VnExpress"
                  autoFocus
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-300 mb-2">
                  URL *
                </label>
                <input
                  type="url"
                  value={newSource.url}
                  onChange={(e) => setNewSource({ ...newSource, url: e.target.value })}
                  className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white placeholder-gray-500"
                  placeholder="https://example.com"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-300 mb-2">
                  Loại nguồn
                </label>
                <select
                  value={newSource.source_type}
                  onChange={(e) => setNewSource({ ...newSource, source_type: e.target.value })}
                  className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white"
                >
                  <option value="website">Website</option>
                  <option value="facebook_page">Facebook Page</option>
                  <option value="facebook_group">Facebook Group</option>
                  <option value="facebook_profile">Facebook Profile</option>
                  <option value="youtube_channel">YouTube Channel</option>
                  <option value="youtube_video">YouTube Video</option>
                  <option value="news">News</option>
                  <option value="rss">RSS Feed</option>
                  <option value="forum">Forum</option>
                  <option value="manual_url">Manual URL</option>
                </select>
              </div>

              {/* Dynamic form based on source type */}
              {/* Website, News, Forum, Manual URL - just need URL */}
              {['website', 'news', 'forum', 'manual_url'].includes(newSource.source_type) && (
                <div className="bg-indigo-500/10 border border-indigo-500/20 rounded-xl p-4">
                  <p className="text-sm text-indigo-300">
                    <strong className="text-indigo-400">Website/News/Forum:</strong> Chỉ cần nhập URL ở trên. Hệ thống sẽ tự động crawl nội dung.
                  </p>
                </div>
              )}

              {/* Facebook - need login credentials */}
              {newSource.source_type.startsWith('facebook_') && (
                <div className="bg-amber-500/10 border border-amber-500/20 rounded-xl p-4 space-y-4">
                  <p className="text-sm text-amber-300 font-medium">
                    <strong className="text-amber-400">Facebook:</strong> Cần thông tin đăng nhập để truy cập nội dung
                  </p>
                  <div>
                    <label className="block text-sm font-medium text-gray-300 mb-1.5">
                      Email/Username Facebook
                    </label>
                    <input
                      type="text"
                      placeholder="email@example.com"
                      className="w-full px-3 py-2 bg-[#1E293B] border border-gray-700 rounded-lg focus:outline-none focus:ring-2 focus:ring-amber-500 text-white placeholder-gray-500"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-300 mb-1.5">
                      Password
                    </label>
                    <input
                      type="password"
                      placeholder="••••••••"
                      className="w-full px-3 py-2 bg-[#1E293B] border border-gray-700 rounded-lg focus:outline-none focus:ring-2 focus:ring-amber-500 text-white placeholder-gray-500"
                    />
                  </div>
                  <p className="text-xs text-gray-400">
                    ⚠️ Thông tin đăng nhập được mã hóa và chỉ dùng để crawl dữ liệu
                  </p>
                </div>
              )}

              {/* YouTube - need API key or login */}
              {newSource.source_type.startsWith('youtube_') && (
                <div className="bg-rose-500/10 border border-rose-500/20 rounded-xl p-4 space-y-4">
                  <p className="text-sm text-rose-300 font-medium">
                    <strong className="text-rose-400">YouTube:</strong> Chọn phương thức truy cập
                  </p>
                  <div>
                    <label className="block text-sm font-medium text-gray-300 mb-1.5">
                      Phương thức
                    </label>
                    <select className="w-full px-3 py-2 bg-[#1E293B] border border-gray-700 rounded-lg focus:outline-none focus:ring-2 focus:ring-rose-500 text-white">
                      <option value="public">Public (không cần đăng nhập)</option>
                      <option value="api_key">YouTube API Key</option>
                      <option value="login">Đăng nhập Google</option>
                    </select>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-300 mb-1.5">
                      YouTube API Key (tùy chọn)
                    </label>
                    <input
                      type="text"
                      placeholder="AIzaSy..."
                      className="w-full px-3 py-2 bg-[#1E293B] border border-gray-700 rounded-lg focus:outline-none focus:ring-2 focus:ring-rose-500 text-white placeholder-gray-500"
                    />
                  </div>
                  <p className="text-xs text-gray-400">
                    💡 API Key giúp tăng giới hạn request. Lấy tại: console.cloud.google.com
                  </p>
                </div>
              )}

              {/* RSS - need feed settings */}
              {newSource.source_type === 'rss' && (
                <div className="bg-orange-500/10 border border-orange-500/20 rounded-xl p-4 space-y-4">
                  <p className="text-sm text-orange-300 font-medium">
                    <strong className="text-orange-400">RSS Feed:</strong> Cấu hình RSS
                  </p>
                  <div>
                    <label className="block text-sm font-medium text-gray-300 mb-1.5">
                      RSS Feed URL
                    </label>
                    <input
                      type="url"
                      placeholder="https://example.com/feed.xml"
                      className="w-full px-3 py-2 bg-[#1E293B] border border-gray-700 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500 text-white placeholder-gray-500"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-300 mb-1.5">
                      Số lượng items tối đa mỗi lần crawl
                    </label>
                    <input
                      type="number"
                      defaultValue={50}
                      min={1}
                      max={500}
                      className="w-full px-3 py-2 bg-[#1E293B] border border-gray-700 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-500 text-white"
                    />
                  </div>
                  <div className="flex items-center">
                    <input
                      type="checkbox"
                      id="rss-full-content"
                      className="w-4 h-4 text-orange-600 bg-gray-800 border-gray-600 rounded focus:ring-orange-500 focus:ring-offset-gray-900"
                    />
                    <label htmlFor="rss-full-content" className="ml-3 text-sm text-gray-300 cursor-pointer">
                      Lấy full content (nếu RSS chỉ có summary)
                    </label>
                  </div>
                </div>
              )}

              {/* Crawl Schedule */}
              <div className="border-t border-gray-800 pt-5 mt-2">
                <h3 className="text-base font-semibold text-white mb-4">Lịch Quét</h3>
                
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-2">
                    Tần suất quét
                  </label>
                  <select
                    value={newSource.crawl_frequency}
                    onChange={(e) => setNewSource({ 
                      ...newSource, 
                      crawl_frequency: e.target.value as 'manual' | 'daily' | 'weekly' | 'monthly' | 'yearly'
                    })}
                    className="w-full px-4 py-2.5 bg-[#1E293B] border border-gray-700 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500 text-white"
                  >
                    <option value="manual">Thủ công (Không tự động quét)</option>
                    <option value="daily">Hằng ngày</option>
                    <option value="weekly">Hằng tuần</option>
                    <option value="monthly">Hằng tháng</option>
                    <option value="yearly">Hằng năm</option>
                  </select>
                </div>

                {/* Schedule Selector Component wrapper in dark mode via CSS global .dark but let's assume it works. The component might need inline fix if it relies on text-gray-700 */}
                <div className="mt-4 schedule-dark-wrapper">
                  <ScheduleSelector
                    frequency={newSource.crawl_frequency}
                    value={newSource.schedule}
                    onChange={(schedule) => setNewSource({ ...newSource, schedule })}
                  />
                </div>
              </div>
            </div>

            <div className="p-6 border-t border-gray-800 bg-[#0B1220]/50 rounded-b-2xl flex justify-end space-x-3 sticky bottom-0">
              <button
                onClick={() => setShowAddModal(false)}
                className="px-5 py-2.5 text-sm font-medium text-gray-300 bg-[#1E293B] border border-gray-700 rounded-xl hover:bg-gray-800 hover:text-white transition-colors"
              >
                Hủy
              </button>
              <button
                onClick={handleAddSource}
                className="px-5 py-2.5 text-sm font-medium text-white bg-indigo-600 rounded-xl hover:bg-indigo-700 shadow-sm shadow-indigo-500/20 transition-all"
              >
                Thêm Nguồn
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

frontend/src/app/dashboard/mentions/[id]:
'use client';

import { useEffect, useState } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { ArrowLeft, AlertTriangle, FileText, ExternalLink, Activity } from 'lucide-react';
import { mentions as mentionsApi, alerts as alertsApi, incidents as incidentsApi } from '@/lib/api';
import toast, { Toaster } from 'react-hot-toast';
import ExecutiveBriefModal from '@/components/dashboard/ExecutiveBriefModal';

export default function MentionDetailPage() {
  const params = useParams();
  const router = useRouter();
  const [mention, setMention] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [isBriefModalOpen, setIsBriefModalOpen] = useState(false);

  useEffect(() => {
    if (params.id) {
      fetchMention(parseInt(params.id as string));
    }
  }, [params.id]);

  const fetchMention = async (id: number) => {
    try {
      setLoading(true);
      const data = await mentionsApi.get(id);
      setMention(data);
    } catch (error: any) {
      console.error('Error fetching mention:', error);
      // Don't toast here — we redirect back immediately, and the toast
      // would linger on the list page, confusing the user.
      router.push('/dashboard/mentions');
    } finally {
      setLoading(false);
    }
  };

  const handleCreateAlert = async () => {
    if (!mention) return;
    
    try {
      await alertsApi.create({
        mention_id: mention.id,
        title: `Alert: ${mention.title || 'No title'}`,
        severity: mention.ai_analysis?.risk_score >= 70 ? 'high' : 'medium',
        message: `Risk score: ${mention.ai_analysis?.risk_score}`
      });
      toast.success('Tạo cảnh báo thành công!');
    } catch (error: any) {
      console.error('Error creating alert:', error);
      toast.error('Lỗi khi tạo cảnh báo');
    }
  };

  const handleCreateIncident = async () => {
    if (!mention) return;
    
    try {
      await incidentsApi.create({
        mention_id: mention.id,
        title: `Incident: ${mention.title || 'No title'}`,
        description: mention.ai_analysis?.summary_vi || ''
      });
      toast.success('Tạo sự cố thành công!');
    } catch (error: any) {
      console.error('Error creating incident:', error);
      toast.error('Lỗi khi tạo sự cố');
    }
  };

  const getSentimentColor = (sentiment: string) => {
    if (sentiment === 'positive') return 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20';
    if (sentiment === 'neutral') return 'bg-gray-800 text-gray-400 border-gray-700';
    if (sentiment === 'negative_low') return 'bg-amber-500/10 text-amber-400 border-amber-500/20';
    if (sentiment === 'negative_medium') return 'bg-orange-500/10 text-orange-400 border-orange-500/20';
    if (sentiment === 'negative_high') return 'bg-rose-500/10 text-rose-400 border-rose-500/20';
    return 'bg-gray-800 text-gray-400 border-gray-700';
  };

  const getRiskColor = (score: number) => {
    if (score >= 80) return 'text-rose-500';
    if (score >= 60) return 'text-orange-500';
    if (score >= 40) return 'text-amber-500';
    return 'text-emerald-500';
  };

  const getRiskBgColor = (score: number) => {
    if (score >= 80) return 'bg-rose-500/10 border-rose-500/20';
    if (score >= 60) return 'bg-orange-500/10 border-orange-500/20';
    if (score >= 40) return 'bg-amber-500/10 border-amber-500/20';
    return 'bg-emerald-500/10 border-emerald-500/20';
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="text-lg text-gray-400 font-medium tracking-wide">Đang tải...</div>
      </div>
    );
  }

  if (!mention) {
    return (
      <div className="text-center py-12">
        <p className="text-gray-400 font-medium tracking-wide">Không tìm thấy mention</p>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <Toaster position="top-right" />
      
      {/* Header */}
      <div className="flex items-center space-x-4 mb-6">
        <button
          onClick={() => router.back()}
          className="p-2 text-gray-400 hover:text-white bg-[#111827] border border-gray-800 hover:bg-gray-800 rounded-xl transition-all shadow-sm"
        >
          <ArrowLeft className="w-5 h-5" />
        </button>
        <div>
          <h1 className="text-2xl font-bold text-white tracking-wide">Chi tiết Mention</h1>
          <p className="text-sm text-gray-400 mt-1 font-mono">ID: {mention.id}</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Main Content */}
        <div className="lg:col-span-2 space-y-6">
          {/* Content Card */}
          <div className="bg-[#111827] border border-gray-800 rounded-xl shadow-sm p-6 sm:p-8">
            <h2 className="text-xl font-bold text-white mb-6 leading-snug">
              {mention.title || 'No title'}
            </h2>
            <div className="prose prose-invert max-w-none">
              <p className="text-gray-300 leading-relaxed whitespace-pre-wrap">
                {mention.content}
              </p>
            </div>
            <div className="mt-8 pt-5 border-t border-gray-800">
              <a 
                href={mention.url} 
                target="_blank" 
                rel="noopener noreferrer"
                className="inline-flex items-center text-indigo-400 hover:text-indigo-300 font-medium transition-colors"
              >
                <ExternalLink className="w-4 h-4 mr-2" />
                Xem nguồn gốc
              </a>
            </div>
          </div>

          {/* Matched Keywords */}
          {mention.matched_keywords && mention.matched_keywords.length > 0 && (
            <div className="bg-[#111827] border border-gray-800 rounded-xl shadow-sm p-6 sm:p-8">
              <h3 className="text-lg font-bold text-white mb-5 flex items-center">Từ khóa khớp</h3>
              <div className="flex flex-wrap gap-2.5">
                {mention.matched_keywords.map((kw: any, idx: number) => (
                  <span key={idx} className="px-3 py-1.5 bg-indigo-500/10 text-indigo-400 text-sm rounded-lg font-semibold tracking-wide border border-indigo-500/20 uppercase">
                    {kw.keyword}
                  </span>
                ))}
              </div>
            </div>
          )}
        </div>

        {/* Sidebar */}
        <div className="space-y-6">
          {/* AI Analysis */}
          {mention.ai_analysis && (
            <div className="bg-[#111827] border border-gray-800 rounded-xl shadow-sm p-6">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-lg font-bold text-white">AI Analysis</h3>
                {(mention.ai_analysis.ai_provider === 'dummy' || mention.ai_analysis.ai_provider === 'dummy_ai') && (
                  <span className="px-2 py-0.5 text-[10px] font-bold tracking-wider uppercase text-orange-400 bg-orange-500/10 rounded-md border border-orange-500/20">
                    DUMMY/DEV
                  </span>
                )}
                {mention.ai_analysis.ai_provider && mention.ai_analysis.ai_provider !== 'dummy' && mention.ai_analysis.ai_provider !== 'dummy_ai' && (
                  <span className="px-2 py-0.5 text-[10px] font-bold tracking-wider uppercase text-indigo-400 bg-indigo-500/10 rounded-md border border-indigo-500/20">
                    {mention.ai_analysis.ai_provider}
                  </span>
                )}
              </div>
              
              {/* Risk Score - Prominent */}
              <div className={`p-5 rounded-xl border mb-6 flex flex-col items-center justify-center ${getRiskBgColor(mention.ai_analysis.risk_score)}`}>
                <div className={`text-4xl font-black ${getRiskColor(mention.ai_analysis.risk_score)}`}>
                  {mention.ai_analysis.risk_score}
                </div>
                <div className="text-xs font-bold tracking-wider uppercase text-gray-500 mt-2">Risk Score</div>
              </div>

              <div className="space-y-4">
                <div className="flex justify-between items-center border-b border-gray-800 pb-3">
                  <span className="text-sm font-medium text-gray-400 uppercase tracking-wider text-[11px]">Sentiment</span>
                  <span className={`px-2.5 py-1 text-[10px] font-bold uppercase tracking-wider rounded-md border ${getSentimentColor(mention.ai_analysis.sentiment)}`}>
                    {mention.ai_analysis.sentiment}
                  </span>
                </div>
                
                <div className="flex justify-between items-center border-b border-gray-800 pb-3">
                  <span className="text-sm font-medium text-gray-400 uppercase tracking-wider text-[11px]">Crisis Level</span>
                  <div className="flex items-center space-x-1.5">
                    {[1, 2, 3, 4, 5].map((level) => (
                      <div
                        key={level}
                        className={`w-2.5 h-2.5 rounded-full ${
                          level <= mention.ai_analysis.crisis_level
                            ? 'bg-rose-500 shadow-[0_0_8px_rgba(244,63,94,0.6)]'
                            : 'bg-gray-800'
                        }`}
                      />
                    ))}
                    <span className="ml-2 text-[11px] font-bold tracking-wider text-white">
                      {mention.ai_analysis.crisis_level}/5
                    </span>
                  </div>
                </div>

                <div className="flex justify-between items-center border-b border-gray-800 pb-3">
                  <span className="text-sm font-medium text-gray-400 uppercase tracking-wider text-[11px]">Suggested Action</span>
                  <span className="text-sm font-semibold text-white capitalize">
                    {mention.ai_analysis.suggested_action?.replace('_', ' ')}
                  </span>
                </div>

                {mention.ai_analysis.responsible_department && (
                  <div className="flex justify-between items-center border-b border-gray-800 pb-3">
                    <span className="text-sm font-medium text-gray-400 uppercase tracking-wider text-[11px]">Department</span>
                    <span className="text-sm font-semibold text-white capitalize">
                      {mention.ai_analysis.responsible_department?.replace('_', ' ')}
                    </span>
                  </div>
                )}

                {mention.ai_analysis.confidence_score && (
                  <div className="flex justify-between items-center">
                    <span className="text-sm font-medium text-gray-400 uppercase tracking-wider text-[11px]">Confidence</span>
                    <span className="text-sm font-bold text-white">
                      {mention.ai_analysis.confidence_score}%
                    </span>
                  </div>
                )}
              </div>

              {mention.ai_analysis.summary_vi && (
                <div className="mt-6 pt-5 border-t border-gray-800">
                  <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-3">Tóm tắt AI:</h4>
                  <p className="text-sm text-gray-300 bg-[#0B1220] border border-gray-800 p-4 rounded-xl leading-relaxed">
                    {mention.ai_analysis.summary_vi}
                  </p>
                </div>
              )}

              {/* Risk-to-Action Engine Block */}
              {mention.ai_analysis.urgency && (
                <div className="mt-6 pt-5 border-t border-gray-800">
                  <h4 className="text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-3 flex items-center">
                    <Activity className="w-3.5 h-3.5 mr-1.5 text-indigo-400" />
                    Risk-to-Action Engine
                  </h4>
                  <div className="bg-[#0B1220] border border-gray-800 p-4 rounded-xl space-y-4">
                    {mention.ai_analysis.why_it_matters && (
                      <div>
                        <span className="text-[10px] font-bold text-gray-500 uppercase block mb-1">Mức độ ảnh hưởng</span>
                        <p className="text-sm text-gray-300">{mention.ai_analysis.why_it_matters}</p>
                      </div>
                    )}
                    <div className="grid grid-cols-2 gap-3">
                      <div>
                        <span className="text-[10px] font-bold text-gray-500 uppercase block mb-1">Độ khẩn cấp</span>
                        <span className={`px-2 py-0.5 text-xs font-semibold rounded-md ${
                          mention.ai_analysis.urgency === 'critical' ? 'bg-rose-500/10 text-rose-400' :
                          mention.ai_analysis.urgency === 'high' ? 'bg-orange-500/10 text-orange-400' :
                          mention.ai_analysis.urgency === 'medium' ? 'bg-amber-500/10 text-amber-400' :
                          'bg-emerald-500/10 text-emerald-400'
                        }`}>
                          {mention.ai_analysis.urgency.toUpperCase()}
                        </span>
                      </div>
                      <div>
                        <span className="text-[10px] font-bold text-gray-500 uppercase block mb-1">Đề xuất xử lý</span>
                        <span className="text-sm font-medium text-white">{mention.ai_analysis.response_type?.replace(/_/g, ' ')}</span>
                      </div>
                      <div>
                        <span className="text-[10px] font-bold text-gray-500 uppercase block mb-1">Người phụ trách (Gợi ý)</span>
                        <span className="text-sm font-medium text-white">{mention.ai_analysis.recommended_owner}</span>
                      </div>
                      <div>
                        <span className="text-[10px] font-bold text-gray-500 uppercase block mb-1">Thời hạn</span>
                        <span className="text-sm font-medium text-white">{mention.ai_analysis.deadline_suggestion}</span>
                      </div>
                    </div>
                    {mention.ai_analysis.escalation_needed && (
                      <div className="pt-2">
                        <span className="inline-flex items-center px-2 py-1 bg-rose-500/10 border border-rose-500/20 text-rose-400 text-xs font-bold rounded">
                          <AlertTriangle className="w-3 h-3 mr-1" />
                          CẦN LEO THANG (ESCALATION REQUIRED)
                        </span>
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Actions */}
          <div className="bg-[#111827] border border-gray-800 rounded-xl shadow-sm p-6">
            <h3 className="text-lg font-bold text-white mb-5">Hành động</h3>
            <div className="space-y-4">
              <button
                onClick={handleCreateAlert}
                className="w-full flex items-center justify-center px-4 py-3 bg-amber-600 text-white rounded-xl hover:bg-amber-700 transition-colors font-semibold shadow-sm shadow-amber-500/20"
              >
                <AlertTriangle className="w-5 h-5 mr-2" />
                Tạo Cảnh Báo
              </button>
              <button
                onClick={() => setIsBriefModalOpen(true)}
                className="flex items-center px-4 py-2.5 bg-indigo-600 hover:bg-indigo-700 text-white text-sm font-semibold rounded-xl shadow-lg shadow-indigo-900/20 transition-all focus:ring-2 focus:ring-indigo-500 focus:outline-none"
              >
                <FileText className="w-4 h-4 mr-2" />
                Tạo Executive Brief
              </button>
              <button
                onClick={handleCreateIncident}
                className="w-full flex items-center justify-center px-4 py-3 bg-rose-600 text-white rounded-xl hover:bg-rose-700 transition-colors font-semibold shadow-sm shadow-rose-500/20"
              >
                <FileText className="w-5 h-5 mr-2" />
                Tạo Sự Cố
              </button>
            </div>
          </div>

          {/* Meta Information */}
          <div className="bg-[#111827] border border-gray-800 rounded-xl shadow-sm p-6">
            <h3 className="text-lg font-bold text-white mb-5">Thông tin</h3>
            <div className="space-y-4 text-sm">
              <div className="flex justify-between items-center">
                <span className="text-gray-400 font-medium">Thu thập:</span>
                <span className="text-white font-medium">
                  {new Date(mention.collected_at).toLocaleString('vi-VN')}
                </span>
              </div>
              {mention.published_at && (
                <div className="flex justify-between items-center">
                  <span className="text-gray-400 font-medium">Xuất bản:</span>
                  <span className="text-white font-medium">
                    {new Date(mention.published_at).toLocaleString('vi-VN')}
                  </span>
                </div>
              )}
              {mention.author && (
                <div className="flex justify-between items-center">
                  <span className="text-gray-400 font-medium">Tác giả:</span>
                  <span className="text-white font-medium">{mention.author}</span>
                </div>
              )}
              <div className="flex justify-between items-center">
                <span className="text-gray-400 font-medium">Source ID:</span>
                <span className="text-white font-mono">{mention.source_id}</span>
              </div>
            </div>
          </div>
        </div>
      </div>

      <ExecutiveBriefModal
        isOpen={isBriefModalOpen}
        onClose={() => setIsBriefModalOpen(false)}
        mentionIds={mention ? [mention.id] : undefined}
      />
    </div>
  );
}

frontend/src/components/dashboard/AiCris:
'use client';

import React from 'react';
import { AlertTriangle, Shield, Zap } from 'lucide-react';

interface ActionItem {
  step: number;
  title: string;
  description: string;
  priority: string; // critical, high, medium, low
}

interface AiCrisisPanelProps {
  keyword: string;
  crisisSummary: string;
  riskLevel: string;          // Low, Medium, High
  actionItems: ActionItem[];
  negativeMentionsCount: number;
  totalMentions: number;
  isLoading: boolean;
}

/**
 * AiCrisisPanel — Elegant AI Insight panel
 * Hiển thị cảnh báo khủng hoảng AI và các bước hành động.
 * 
 * Chỉ hiển thị khi risk_level là "Medium" hoặc "High".
 * Sử dụng glassmorphism + animated gradient border cho High risk.
 */
export default function AiCrisisPanel({
  keyword,
  crisisSummary,
  riskLevel,
  actionItems,
  negativeMentionsCount,
  totalMentions,
  isLoading,
}: AiCrisisPanelProps) {
  // Chỉ hiển thị khi risk >= Medium
  if (!isLoading && riskLevel === 'Low') {
    return null;
  }

  if (isLoading) {
    return (
      <div className="rounded-2xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 p-6">
        <div className="flex items-center gap-3 mb-4">
          <div className="w-10 h-10 bg-gray-200 dark:bg-gray-700 rounded-xl animate-pulse" />
          <div className="h-5 w-48 bg-gray-200 dark:bg-gray-700 rounded animate-pulse" />
        </div>
        <div className="space-y-2">
          <div className="h-4 w-full bg-gray-100 dark:bg-gray-700/50 rounded animate-pulse" />
          <div className="h-4 w-3/4 bg-gray-100 dark:bg-gray-700/50 rounded animate-pulse" />
        </div>
      </div>
    );
  }

  const isHigh = riskLevel === 'High';

  // Risk level badge config
  const riskConfig = {
    High: {
      bgGradient: 'from-red-500/10 via-red-500/5 to-orange-500/10',
      borderColor: 'border-red-500/30',
      badgeBg: 'bg-red-500',
      badgeText: 'Cao',
      icon: AlertTriangle,
      iconColor: 'text-red-500',
      glowColor: 'shadow-red-500/20',
    },
    Medium: {
      bgGradient: 'from-amber-500/10 via-amber-500/5 to-yellow-500/10',
      borderColor: 'border-amber-500/30',
      badgeBg: 'bg-amber-500',
      badgeText: 'Trung bình',
      icon: Zap,
      iconColor: 'text-amber-500',
      glowColor: 'shadow-amber-500/20',
    },
    Low: {
      bgGradient: 'from-emerald-500/10 via-emerald-500/5 to-green-500/10',
      borderColor: 'border-emerald-500/30',
      badgeBg: 'bg-emerald-500',
      badgeText: 'Thấp',
      icon: Shield,
      iconColor: 'text-emerald-500',
      glowColor: 'shadow-emerald-500/10',
    },
  };

  const config = riskConfig[riskLevel as keyof typeof riskConfig] || riskConfig.Low;
  const RiskIcon = config.icon;

  // Priority badge colors
  const priorityColors: Record<string, string> = {
    critical: 'bg-red-500 text-white',
    high: 'bg-orange-500 text-white',
    medium: 'bg-amber-500 text-white',
    low: 'bg-gray-400 text-white',
  };

  return (
    <div
      className={`
        relative rounded-2xl overflow-hidden
        border ${config.borderColor}
        bg-gradient-to-br ${config.bgGradient}
        backdrop-blur-sm
        shadow-lg ${config.glowColor}
        transition-all duration-500 ease-out
      `}
      style={{
        animation: 'fadeSlideUp 0.5s ease-out',
      }}
    >
      {/* Animated gradient border for High risk */}
      {isHigh && (
        <div className="absolute inset-0 rounded-2xl border-2 border-red-500/40 animate-pulse pointer-events-none" />
      )}

      <div className="relative p-6">
        {/* Header */}
        <div className="flex items-center justify-between mb-5">
          <div className="flex items-center gap-3">
            <div
              className={`
                p-2.5 rounded-xl
                ${isHigh ? 'bg-red-500/20 animate-pulse' : 'bg-amber-500/20'}
              `}
            >
              <RiskIcon className={`w-6 h-6 ${config.iconColor}`} />
            </div>
            <div>
              <h3 className="text-lg font-bold text-gray-900 dark:text-white">
                🤖 Phân Tích AI — Cảnh Báo Khủng Hoảng
              </h3>
              <p className="text-xs text-gray-500 dark:text-gray-400">
                Từ khóa: <span className="font-medium">{keyword}</span>
              </p>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <span
              className={`
                px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wide
                ${config.badgeBg} text-white shadow-sm
              `}
            >
              {config.badgeText}
            </span>
            <span className="text-xs text-gray-500 dark:text-gray-400">
              {negativeMentionsCount}/{totalMentions} tiêu cực
            </span>
          </div>
        </div>

        {/* Crisis Summary */}
        <div className="bg-white/60 dark:bg-gray-800/60 backdrop-blur-sm rounded-xl p-4 mb-5 border border-gray-200/50 dark:border-gray-700/50">
          <p className="text-sm text-gray-800 dark:text-gray-200 leading-relaxed">
            {crisisSummary}
          </p>
        </div>

        {/* Action Items */}
        {actionItems.length > 0 && (
          <div>
            <h4 className="text-sm font-semibold text-gray-700 dark:text-gray-300 mb-3 flex items-center gap-2">
              <span>📋</span> Hành Động Đề Xuất
            </h4>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
              {actionItems.map((item) => (
                <div
                  key={item.step}
                  className="
                    bg-white/80 dark:bg-gray-800/80 backdrop-blur-sm
                    rounded-xl p-4
                    border border-gray-200/50 dark:border-gray-700/50
                    hover:shadow-md transition-shadow duration-200
                    group
                  "
                >
                  <div className="flex items-center gap-2 mb-2">
                    <span className="flex items-center justify-center w-7 h-7 rounded-lg bg-indigo-500 text-white text-xs font-bold">
                      {item.step}
                    </span>
                    <span
                      className={`
                        px-2 py-0.5 rounded text-[10px] font-semibold uppercase
                        ${priorityColors[item.priority] || priorityColors.low}
                      `}
                    >
                      {item.priority === 'critical'
                        ? 'Khẩn cấp'
                        : item.priority === 'high'
                        ? 'Cao'
                        : item.priority === 'medium'
                        ? 'Vừa'
                        : 'Thấp'}
                    </span>
                  </div>
                  <h5 className="text-sm font-semibold text-gray-800 dark:text-gray-200 mb-1">
                    {item.title}
                  </h5>
                  <p className="text-xs text-gray-500 dark:text-gray-400 leading-relaxed">
                    {item.description}
                  </p>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

frontend/src/components/dashboard/AlertC:
import React, { useState } from 'react';
import { AlertTriangle, CheckCircle, ShieldAlert, XCircle, Info } from 'lucide-react';
import { SeverityBadge } from './Badges';
import DashboardQuickActionButton from './DashboardQuickActionButton';
import { alerts } from '@/lib/api';
import toast from 'react-hot-toast';

interface AlertCardProps {
  alert: any;
  onActionComplete: () => void;
  userRole?: string;
}

export default function AlertCard({ alert, onActionComplete, userRole }: AlertCardProps) {
  const [loadingAction, setLoadingAction] = useState<string | null>(null);

  const canAcknowledge = ['analyst', 'manager', 'admin', 'super_admin'].includes(userRole || '');
  const canEscalate = ['manager', 'admin', 'super_admin'].includes(userRole || '');

  const handleAction = async (action: string, apiCall: () => Promise<any>, successMsg: string) => {
    setLoadingAction(action);
    try {
      await apiCall();
      toast.success(successMsg);
      onActionComplete();
    } catch (error: any) {
      toast.error(error?.response?.data?.detail || 'Có lỗi xảy ra');
    } finally {
      setLoadingAction(null);
    }
  };

  const isResolved = alert.status === 'resolved' || alert.status === 'ignored';

  return (
    <div className={`rounded-xl shadow-sm border p-4 transition-all ${
      alert.severity === 'critical' ? 'bg-rose-500/5 border-rose-500/20' : 
      alert.severity === 'high' ? 'bg-amber-500/5 border-amber-500/20' : 
      'bg-[#1E293B] border-gray-800'
    } ${isResolved ? 'opacity-75' : ''}`}>
      
      <div className="flex items-start space-x-3">
        <div className={`mt-0.5 p-2 rounded-xl border ${
          alert.severity === 'critical' ? 'bg-rose-500/10 text-rose-400 border-rose-500/20' :
          alert.severity === 'high' ? 'bg-amber-500/10 text-amber-400 border-amber-500/20' :
          alert.severity === 'medium' ? 'bg-yellow-500/10 text-yellow-400 border-yellow-500/20' :
          'bg-indigo-500/10 text-indigo-400 border-indigo-500/20'
        }`}>
          <AlertTriangle className="w-5 h-5" />
        </div>
        
        <div className="flex-1 min-w-0">
          <div className="flex items-center justify-between">
            <h3 className="font-semibold text-white tracking-wide truncate pr-2">
              {alert.title}
            </h3>
            <SeverityBadge severity={alert.severity} />
          </div>
          
          <p className="mt-1.5 text-sm text-gray-400 line-clamp-2">
            {alert.message || alert.reason || 'Không có mô tả'}
          </p>
          
          <div className="mt-3 flex flex-wrap items-center gap-3 text-xs font-medium text-gray-500">
            <span className="flex items-center">
              <span className={`w-2 h-2 rounded-full mr-2 shadow-sm ${
                alert.status === 'new' ? 'bg-indigo-500 shadow-indigo-500/50' :
                alert.status === 'acknowledged' ? 'bg-amber-500 shadow-amber-500/50' :
                alert.status === 'resolved' ? 'bg-emerald-500 shadow-emerald-500/50' :
                'bg-gray-500'
              }`}></span>
              {alert.status.toUpperCase()}
            </span>
            <span className="text-gray-700">•</span>
            <span className="tracking-wide">{new Date(alert.created_at).toLocaleString('vi-VN')}</span>
            {alert.mention_id && (
              <>
                <span className="text-gray-700">•</span>
                <a href={`/dashboard/mentions/${alert.mention_id}`} target="_blank" rel="noopener noreferrer" className="text-indigo-400 hover:text-indigo-300 hover:underline flex items-center transition-colors">
                  Xem mention <Info className="w-3 h-3 ml-1" />
                </a>
              </>
            )}
          </div>

          {!isResolved && (
            <div className="mt-4 pt-4 border-t border-gray-800/80 flex flex-wrap gap-3">
              {alert.status === 'new' && canAcknowledge && (
                <DashboardQuickActionButton
                  label="Đã tiếp nhận"
                  icon={CheckCircle}
                  onClick={() => handleAction('ack', () => alerts.acknowledge(alert.id), 'Đã tiếp nhận cảnh báo')}
                  isLoading={loadingAction === 'ack'}
                  variant="primary"
                />
              )}
              
              {canEscalate && (
                <DashboardQuickActionButton
                  label="Tạo sự cố"
                  icon={ShieldAlert}
                  onClick={() => handleAction('incident', () => alerts.createIncident(alert.id), 'Đã chuyển thành sự cố')}
                  isLoading={loadingAction === 'incident'}
                  variant="danger"
                />
              )}
              
              {canEscalate && (
                <DashboardQuickActionButton
                  label="Bỏ qua"
                  icon={XCircle}
                  onClick={() => handleAction('ignore', () => alerts.ignore(alert.id), 'Đã bỏ qua cảnh báo')}
                  isLoading={loadingAction === 'ignore'}
                  variant="ghost"
                />
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

