'use client';

import React from 'react';
import { LucideIcon } from 'lucide-react';

interface MonitorMetricCardProps {
  title: string;
  value: string | number;
  subtitle?: string;
  icon: LucideIcon;
  gradient: string;       // Tailwind gradient classes
  iconBg: string;         // Icon background color
  textColor?: string;     // Value text color
  pulse?: boolean;        // Pulse animation for critical metrics
}

/**
 * MonitorMetricCard — Premium KPI card component
 * Thẻ hiển thị chỉ số quan trọng với gradient background và micro-animations.
 * 
 * Sử dụng:
 *   <MonitorMetricCard
 *     title="Tổng Đề Cập"
 *     value={1234}
 *     icon={MessageCircle}
 *     gradient="from-blue-500 to-indigo-600"
 *     iconBg="bg-blue-400/30"
 *   />
 */
export default function MonitorMetricCard({
  title,
  value,
  subtitle,
  icon: Icon,
  gradient,
  iconBg,
  textColor = 'text-white',
  pulse = false,
}: MonitorMetricCardProps) {
  return (
    <div
      className={`
        relative overflow-hidden rounded-2xl p-6
        bg-gradient-to-br ${gradient}
        shadow-lg hover:shadow-xl
        transform hover:scale-[1.02] transition-all duration-300
        group
      `}
    >
      {/* Background decorative circles */}
      <div className="absolute -top-4 -right-4 w-24 h-24 bg-white/10 rounded-full blur-xl group-hover:scale-125 transition-transform duration-500" />
      <div className="absolute -bottom-2 -left-2 w-16 h-16 bg-white/5 rounded-full blur-lg" />

      <div className="relative flex items-start justify-between">
        <div className="flex-1">
          <p className="text-sm font-medium text-white/80 mb-1">{title}</p>
          <p
            className={`text-3xl font-bold ${textColor} tracking-tight ${
              pulse ? 'animate-pulse' : ''
            }`}
          >
            {typeof value === 'number' ? value.toLocaleString('vi-VN') : value}
          </p>
          {subtitle && (
            <p className="text-xs text-white/60 mt-1">{subtitle}</p>
          )}
        </div>

        <div
          className={`
            ${iconBg} rounded-xl p-3
            group-hover:scale-110 transition-transform duration-300
          `}
        >
          <Icon className="w-6 h-6 text-white" />
        </div>
      </div>
    </div>
  );
}

'use client';

import React from 'react';
import {
  PieChart,
  Pie,
  Cell,
  ResponsiveContainer,
  Tooltip,
  Legend,
} from 'recharts';

interface SentimentBreakdown {
  positive_count: number;
  negative_count: number;
  neutral_count: number;
  positive_pct: number;
  negative_pct: number;
  neutral_pct: number;
}

interface MonitorSentimentChartProps {
  data: SentimentBreakdown | null;
  isLoading: boolean;
}

/**
 * MonitorSentimentChart — Enhanced donut chart with center label
 * Biểu đồ tròn sentiment với nhãn trung tâm hiển thị tổng số.
 * 
 * Color palette sử dụng HSL-tailored colors:
 * - Tích cực: Emerald gradient (#10B981 → #34D399)
 * - Trung lập: Slate (#94A3B8)
 * - Tiêu cực: Rose gradient (#F43F5E → #FB7185)
 */
export default function MonitorSentimentChart({
  data,
  isLoading,
}: MonitorSentimentChartProps) {
  if (isLoading) {
    return (
      <div className="h-72 flex items-center justify-center">
        <div className="w-10 h-10 border-4 border-blue-500/30 border-t-blue-500 rounded-full animate-spin" />
      </div>
    );
  }

  if (!data || (data.positive_count + data.negative_count + data.neutral_count) === 0) {
    return (
      <div className="h-72 flex flex-col items-center justify-center text-gray-400">
        <svg className="w-12 h-12 mb-3 opacity-40" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M11 3.055A9.001 9.001 0 1020.945 13H11V3.055z" />
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M20.488 9H15V3.512A9.025 9.025 0 0120.488 9z" />
        </svg>
        <p className="text-sm">Chưa có dữ liệu sắc thái</p>
      </div>
    );
  }

  const total = data.positive_count + data.negative_count + data.neutral_count;

  const chartData = [
    { name: 'Tích cực', value: data.positive_count, color: '#10B981', pct: data.positive_pct },
    { name: 'Trung lập', value: data.neutral_count, color: '#94A3B8', pct: data.neutral_pct },
    { name: 'Tiêu cực', value: data.negative_count, color: '#F43F5E', pct: data.negative_pct },
  ].filter((item) => item.value > 0);

  const CustomTooltip = ({ active, payload }: any) => {
    if (active && payload && payload.length) {
      const entry = payload[0].payload;
      return (
        <div className="bg-gray-900 text-white px-4 py-2.5 rounded-xl shadow-xl border border-gray-700/50 text-sm">
          <p className="font-semibold">{entry.name}</p>
          <p className="text-gray-300">
            {entry.value} đề cập ({entry.pct}%)
          </p>
        </div>
      );
    }
    return null;
  };

  const renderCustomLabel = ({
    cx,
    cy,
  }: any) => {
    return (
      <g>
        <text
          x={cx}
          y={cy - 8}
          textAnchor="middle"
          dominantBaseline="central"
          className="fill-gray-800 dark:fill-gray-200 text-2xl font-bold"
          style={{ fontSize: '24px', fontWeight: 700 }}
        >
          {total.toLocaleString('vi-VN')}
        </text>
        <text
          x={cx}
          y={cy + 14}
          textAnchor="middle"
          dominantBaseline="central"
          className="fill-gray-500 text-xs"
          style={{ fontSize: '11px' }}
        >
          đề cập
        </text>
      </g>
    );
  };

  return (
    <div className="h-72 w-full">
      <ResponsiveContainer width="100%" height="100%">
        <PieChart>
          <Pie
            data={chartData}
            cx="50%"
            cy="50%"
            innerRadius={65}
            outerRadius={95}
            paddingAngle={3}
            dataKey="value"
            strokeWidth={0}
            animationBegin={0}
            animationDuration={800}
            animationEasing="ease-out"
            label={false}
          >
            {chartData.map((entry, index) => (
              <Cell
                key={`cell-${index}`}
                fill={entry.color}
                className="hover:opacity-80 transition-opacity duration-200 cursor-pointer"
              />
            ))}
          </Pie>
          {/* Center label */}
          <Pie
            data={[{ value: 1 }]}
            cx="50%"
            cy="50%"
            innerRadius={0}
            outerRadius={0}
            dataKey="value"
            label={renderCustomLabel}
            isAnimationActive={false}
          >
            <Cell fill="transparent" />
          </Pie>
          <Tooltip content={<CustomTooltip />} />
          <Legend
            verticalAlign="bottom"
            height={36}
            iconType="circle"
            iconSize={10}
            formatter={(value: string) => (
              <span className="text-sm text-gray-600 dark:text-gray-400">{value}</span>
            )}
          />
        </PieChart>
      </ResponsiveContainer>
    </div>
  );
}

'use client';

import React from 'react';
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  Legend,
} from 'recharts';

interface VolatilityDataPoint {
  date: string;
  total: number;
  positive: number;
  negative: number;
  neutral: number;
}

interface MonitorVolatilityChartProps {
  data: VolatilityDataPoint[];
  isLoading: boolean;
}

/**
 * MonitorVolatilityChart — Area chart for mention volatility over time
 * Biểu đồ vùng hiển thị biến động đề cập theo ngày.
 * Sử dụng gradient fill dưới đường line để tạo hiệu ứng premium.
 */
export default function MonitorVolatilityChart({
  data,
  isLoading,
}: MonitorVolatilityChartProps) {
  if (isLoading) {
    return (
      <div className="h-72 flex items-center justify-center">
        <div className="w-10 h-10 border-4 border-indigo-500/30 border-t-indigo-500 rounded-full animate-spin" />
      </div>
    );
  }

  if (!data || data.length === 0) {
    return (
      <div className="h-72 flex flex-col items-center justify-center text-gray-400">
        <svg className="w-12 h-12 mb-3 opacity-40" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M7 12l3-3 3 3 4-4M8 21l4-4 4 4M3 4h18M4 4h16v12a1 1 0 01-1 1H5a1 1 0 01-1-1V4z" />
        </svg>
        <p className="text-sm">Chưa có dữ liệu biến động</p>
      </div>
    );
  }

  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      // Format date dd/mm
      let dateStr = label;
      if (typeof label === 'string' && label.includes('-')) {
        const parts = label.split('-');
        if (parts.length === 3) dateStr = `${parts[2]}/${parts[1]}`;
      }

      return (
        <div className="bg-gray-900 text-white px-4 py-3 rounded-xl shadow-xl border border-gray-700/50 text-sm min-w-[160px]">
          <p className="font-semibold mb-2 text-gray-300">📅 {dateStr}</p>
          {payload.map((entry: any, index: number) => (
            <div key={index} className="flex justify-between items-center gap-4 py-0.5">
              <div className="flex items-center gap-2">
                <div
                  className="w-2.5 h-2.5 rounded-full"
                  style={{ backgroundColor: entry.color }}
                />
                <span className="text-gray-300">{entry.name}</span>
              </div>
              <span className="font-medium">{entry.value}</span>
            </div>
          ))}
        </div>
      );
    }
    return null;
  };

  return (
    <div className="h-72 w-full">
      <ResponsiveContainer width="100%" height="100%">
        <AreaChart data={data} margin={{ top: 5, right: 20, left: 0, bottom: 5 }}>
          {/* Gradient definitions */}
          <defs>
            <linearGradient id="gradTotal" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#6366F1" stopOpacity={0.3} />
              <stop offset="95%" stopColor="#6366F1" stopOpacity={0.02} />
            </linearGradient>
            <linearGradient id="gradNegative" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#F43F5E" stopOpacity={0.25} />
              <stop offset="95%" stopColor="#F43F5E" stopOpacity={0.02} />
            </linearGradient>
            <linearGradient id="gradPositive" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#10B981" stopOpacity={0.2} />
              <stop offset="95%" stopColor="#10B981" stopOpacity={0.02} />
            </linearGradient>
          </defs>

          <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#E5E7EB" strokeOpacity={0.5} />
          <XAxis
            dataKey="date"
            tick={{ fill: '#9CA3AF', fontSize: 12 }}
            tickLine={false}
            axisLine={false}
            tickFormatter={(value) => {
              if (typeof value === 'string' && value.includes('-')) {
                const parts = value.split('-');
                if (parts.length === 3) return `${parts[2]}/${parts[1]}`;
              }
              return value;
            }}
          />
          <YAxis
            tick={{ fill: '#9CA3AF', fontSize: 12 }}
            tickLine={false}
            axisLine={false}
            allowDecimals={false}
          />
          <Tooltip content={<CustomTooltip />} />
          <Legend
            wrapperStyle={{ paddingTop: '16px' }}
            iconType="circle"
            iconSize={8}
            formatter={(value: string) => (
              <span className="text-sm text-gray-600 dark:text-gray-400">{value}</span>
            )}
          />

          <Area
            type="monotone"
            name="Tổng"
            dataKey="total"
            stroke="#6366F1"
            strokeWidth={2.5}
            fill="url(#gradTotal)"
            dot={false}
            activeDot={{ r: 5, strokeWidth: 2, stroke: '#6366F1', fill: '#fff' }}
            animationDuration={1000}
          />
          <Area
            type="monotone"
            name="Tiêu cực"
            dataKey="negative"
            stroke="#F43F5E"
            strokeWidth={2}
            fill="url(#gradNegative)"
            dot={false}
            activeDot={{ r: 4, strokeWidth: 2, stroke: '#F43F5E', fill: '#fff' }}
            animationDuration={1200}
          />
          <Area
            type="monotone"
            name="Tích cực"
            dataKey="positive"
            stroke="#10B981"
            strokeWidth={2}
            fill="url(#gradPositive)"
            dot={false}
            activeDot={{ r: 4, strokeWidth: 2, stroke: '#10B981', fill: '#fff' }}
            animationDuration={1400}
          />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
}

